-- Poems batch 424
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-5578','金盏儿・风逼透绣罗衾，风刮散楚台云。檐间铁马风敲韵，风摇闲阶翠竹','贯云石','元','元曲','yuanqu','','[]','不堪闻。',28,'元曲/yuanqu.json','["不堪闻。", "风筛帘影动，风传漏声频。", "风熏花气爽，风弄月华昏。"]'),
('yuanqu-5579','后庭花・兽炉中香倦焚，银台上灯渐昏。罗帏里和衣睡，纱窗外曙色分。','贯云石','元','元曲','yuanqu','','[]','想情人，起来时分，蹀金莲搓玉笋。',16,'元曲/yuanqu.json','["想情人，起来时分，蹀金莲搓玉笋。"]'),
('yuanqu-5580','赚煞・捱的到天明，却有谁亻秋问？咋夜和衣睡把罗裙皱损。一面残妆空','贯云石','元','元曲','yuanqu','','[]','泪痕，日高也深院无人。',55,'元曲/yuanqu.json','["泪痕，日高也深院无人。", "掩重门，烦恼向谁论？独对菱花整乱云。", "恰待向瘦庞儿上傅粉，欲梳妆却心困，气长吁呵的镜儿昏。"]'),
('yuanqu-5581','南吕・一枝花离闷','贯云石','元','元曲','yuanqu','','[]','柳垂翡翠条，花落胭脂瓣。',57,'元曲/yuanqu.json','["柳垂翡翠条，花落胭脂瓣。", "绿窗绒缕淡，粉脸泪珠弹，洒竹成斑。", "宝钏松冰腕，蛾眉淡远山。", "常言道好事多悭，陡恁的千难万难。"]'),
('yuanqu-5582','梁州・卜龟卦铜腥玉笋，盼鸿书目断云山。别离情绪谁曾惯！这些时银筝','贯云石','元','元曲','yuanqu','','[]','懒按，锦瑟慵弹，玉箫倦品，宝鉴羞观。',95,'元曲/yuanqu.json','["懒按，锦瑟慵弹，玉箫倦品，宝鉴羞观。", "病恹恹瘦损容颜，闷昏昏多少愁烦。", "花钿坠懒贴香腮，衫袖湿镇淹泪眼，玉簪斜倦整云鬟。", "近间，坐间。", "用工夫修下封鸳鸯缄，无处倩鱼雁。", "有万种凄凉不可堪，何日回还？。"]'),
('yuanqu-5583','骂玉郎・杨花满院东风散，恰才这微雨过燕莺闲，罗帏寂寞空长叹。春色','贯云石','元','元曲','yuanqu','','[]','昏，情意懒，芳心惮。',10,'元曲/yuanqu.json','["昏，情意懒，芳心惮。"]'),
('yuanqu-5584','感皇恩・呀！则我这春意阑珊，莺老花残。一帘风，三月雨，五更寒。闪','贯云石','元','元曲','yuanqu','','[]','的我鸾孤凤单，枕剩衾寒。',24,'元曲/yuanqu.json','["的我鸾孤凤单，枕剩衾寒。", "梨花院，采茶歌，凭阑干。"]'),
('yuanqu-5585','采茶歌・望长安，盼雕鞍，夕阳花草树遮山。叠翠堆岚凝望眼，则我这薄','贯云石','元','元曲','yuanqu','','[]','情何处走云山？。',8,'元曲/yuanqu.json','["情何处走云山？。"]'),
('yuanqu-5586','尾声・半帘红日愁天晚，一盏孤灯照夜阑，全不似当时旧风范。绣床又倦','贯云石','元','元曲','yuanqu','','[]','攀，梳妆又意懒，瘦怯怯裙腰儿旋旋的趱。',19,'元曲/yuanqu.json','["攀，梳妆又意懒，瘦怯怯裙腰儿旋旋的趱。"]'),
('yuanqu-5587','中吕・粉蝶儿北','贯云石','元','元曲','yuanqu','','[]','描不上小扇轻罗，你便是真蓬莱赛他不过，虽然是比不的百二山河。',63,'元曲/yuanqu.json','["描不上小扇轻罗，你便是真蓬莱赛他不过，虽然是比不的百二山河。", "一壁厢嵌平堤，连绿野，端的有亭台百座。", "暗想东城、逋仙诗有谁酬和？。"]'),
('yuanqu-5588','好事近・南・谩说凤凰坡，怎比繁华江左？无穷千古，真个是胜迹极多。','贯云石','元','元曲','yuanqu','','[]','烟笼雾锁，绕六桥翠障如螺座。',30,'元曲/yuanqu.json','["烟笼雾锁，绕六桥翠障如螺座。", "青霭霭山抹柔蓝，碧澄澄水泛金波。"]'),
('yuanqu-5589','料峭东风・南・缘何，乐事赏心多？诗朋酒侣吟哦，花浓酒艳，破除万事','贯云石','元','元曲','yuanqu','','[]','无过。',32,'元曲/yuanqu.json','["无过。", "嬉游玩赏，对清风明月安然坐。", "任春夏秋月冬天，适兴四时皆可。"]'),
('yuanqu-5590','斗鹌鹑・北・闹穰穰的急管繁弦，齐臻臻的兰舟画舸，娇滴滴粉黛相连，','贯云石','元','元曲','yuanqu','','[]','颤巍巍翠云翠云万朵。',44,'元曲/yuanqu.json','["颤巍巍翠云翠云万朵。", "端的是洗古磨今锦绣窝，你不信试觑波。", "绿依依杨柳千株，红馥馥芙渠万朵。"]'),
('yuanqu-5591','上小楼・北・密匝匝那一坨，疏刺刺这几窝。我这里对着晴岚，倚着青山，','贯云石','元','元曲','yuanqu','','[]','湛着清波。',31,'元曲/yuanqu.json','["湛着清波。", "微雨初收，微烟初散，微风初过，却正是再休题淡妆浓抹。"]'),
('yuanqu-5592','扑灯蛾・南・叠叠层楼画阁，簇簇奇花异果。远远的绿莎茵，茸茸的芳草','贯云石','元','元曲','yuanqu','','[]','坡，圪蹬的马蹄踏破。',45,'元曲/yuanqu.json','["坡，圪蹬的马蹄踏破。", "隐隐似长桥跨波，细袅袅绿绿金波。", "迢迢似渔舟钓艇，碧澄澄满船雨笠共烟蓑。"]'),
('yuanqu-5594','大石调・好观音怨恨','贯云石','元','元曲','yuanqu','','[]','先自相逢同欢偶，无妨碍燕侣莺俦。',36,'元曲/yuanqu.json','["先自相逢同欢偶，无妨碍燕侣莺俦。", "并坐同肩共携手，恩情厚，夫妇般相看的好。"]'),
('yuanqu-5595','幺・打听的新来迷歌酒，风闻的别染着个娇羞。弃旧怜新自来有，铁心肠','贯云石','元','元曲','yuanqu','','[]','全不想些儿旧。',7,'元曲/yuanqu.json','["全不想些儿旧。"]'),
('yuanqu-5597','越调・斗鹌鹑忆别','贯云石','元','元曲','yuanqu','','[]','良友曾题，佳人所为。',48,'元曲/yuanqu.json','["良友曾题，佳人所为。", "袅袅婷婷，姿姿媚媚。", "体态温柔，心肠老实。", "件件习，事事知。", "妙舞偏宜，清歌更美。"]'),
('yuanqu-5598','紫花儿・一头相见，两意相投，百步相随。去秋同会，重午别离。伤悲，','贯云石','元','元曲','yuanqu','','[]','和泪和愁饮酒杯。',23,'元曲/yuanqu.json','["和泪和愁饮酒杯。", "后约何期，举目长亭，执行临岐。"]'),
('yuanqu-5600','调笑令・柳七，《乐章集》，把臂双歌真先味。幽欢美爱成佳配，效连理','贯云石','元','元曲','yuanqu','','[]','鹣鹣比翼。',21,'元曲/yuanqu.json','["鹣鹣比翼。", "云窗共寝闻子规，似繁华晓梦惊回。"]'),
('yuanqu-5601','秃厮儿・出郡城愁临浙水，寓钱塘闷度朝夕，匆匆一鞭行色催。洒梨花，','贯云石','元','元曲','yuanqu','','[]','雨霏霏，寒食。',7,'元曲/yuanqu.json','["雨霏霏，寒食。"]'),
('yuanqu-5602','圣药王・风物熙，丽日迟，连天芳草正萋萋。客万里，人九嶷，遥岑十二','贯云石','元','元曲','yuanqu','','[]','远烟迷，生隔断武陵溪。',11,'元曲/yuanqu.json','["远烟迷，生隔断武陵溪。"]'),
('yuanqu-5603','尾・玉人别后空相忆，古犹今之视昔。暮雨楚台云，桃花洞天水。佳偶','贯云石','元','元曲','yuanqu','','[]','国色天香，冰肌玉骨。',48,'元曲/yuanqu.json','["国色天香，冰肌玉骨。", "燕语莺吟，鸾歌凤舞，夜月春风，朝云暮雨。", "美眷爱，俏伴侣。", "叶落归秋，花生满路。"]'),
('yuanqu-5605','天净沙・虽然似水如鱼，甚世曾少实多虚，更有闲言剩语。若将他辜负，','贯云石','元','元曲','yuanqu','','[]','待古里不信神佛。',8,'元曲/yuanqu.json','["待古里不信神佛。"]'),
('yuanqu-5606','小桃红・志诚惠性压其余，无半米儿亏人处。觅便寻芳厮照觑。要欢娱，','贯云石','元','元曲','yuanqu','','[]','看时相见偷圆聚。',25,'元曲/yuanqu.json','["看时相见偷圆聚。", "知心可腹，牵肠割肚，不枉了用工夫。"]'),
('yuanqu-5607','尾・锦纹封寄情缘簿，罗帕留香信物。常想着相见时话儿甜，早忘了星前','贯云石','元','元曲','yuanqu','','[]','月下苦。',4,'元曲/yuanqu.json','["月下苦。"]'),
('yuanqu-5608','双调・新水令皇都元日','贯云石','元','元曲','yuanqu','','[]','郁葱佳气蔼寰区，庆丰年太平时序。',37,'元曲/yuanqu.json','["郁葱佳气蔼寰区，庆丰年太平时序。", "民有感，国无虞。", "瞻仰皇都，圣天子有百灵助。"]'),
('yuanqu-5609','搅筝琶・江山富，天下总欣伏。忠孝宽仁，雄文壮武。功业振乾坤，军尽','贯云石','元','元曲','yuanqu','','[]','欢娱，民亦安居。',24,'元曲/yuanqu.json','["欢娱，民亦安居。", "军民都托赖着我天子福，同乐蓬壶。"]'),
('yuanqu-5610','殿前欢・赛唐虞，大元至大古今无。架海梁对着檠天柱，玉带金符。庆风','贯云石','元','元曲','yuanqu','','[]','云会龙虎，万户侯千钟录，播四海光千古。',29,'元曲/yuanqu.json','["云会龙虎，万户侯千钟录，播四海光千古。", "三阳交泰，五谷时熟。"]'),
('yuanqu-5611','鸳鸯煞・梅花枝上春光露，椒盘杯里香风度。帐设鲛绡，帘卷虾须。唱道','贯云石','元','元曲','yuanqu','','[]','天赐长生，人皆赞祝。',36,'元曲/yuanqu.json','["天赐长生，人皆赞祝。", "道德巍巍，众臣等蒙恩露。", "拜舞嵩呼，万万岁当今圣明主。"]'),
('yuanqu-5612','双调・醉春风','贯云石','元','元曲','yuanqu','','[]','羞画远山眉，不タ宫样妆，平白地招揽这场愁。',42,'元曲/yuanqu.json','["羞画远山眉，不タ宫样妆，平白地招揽这场愁。", "枉了那旧日恩情，旧时风韵，直恁么改模夺样。"]'),
('yuanqu-5613','间金四块玉・冤家早是没胆量，遭逢着很毒爹娘。赤紧地家私十分怏，生','贯云石','元','元曲','yuanqu','','[]','纽做水远山长。',7,'元曲/yuanqu.json','["纽做水远山长。"]'),
('yuanqu-5614','减字木兰花・早是愁怀百倍伤，那更值秋光，逐朝倚定门儿望。怯昏黄，','贯云石','元','元曲','yuanqu','','[]','怕的是塞角韵悠扬。',9,'元曲/yuanqu.json','["怕的是塞角韵悠扬。"]'),
('yuanqu-5615','卖花声煞・簌朱帘猛然离了绣幌，携手相将入洞房。欲诉相思晓鸡唱，好','贯云石','元','元曲','yuanqu','','[]','梦惊回泪万行，都滴在枕头儿上。',15,'元曲/yuanqu.json','["梦惊回泪万行，都滴在枕头儿上。"]'),
('yuanqu-5616','梁州・叹落落情怀不已，恨匆匆岁月何之。拥并也似一片闲愁，撺掇出伤','贯云石','元','元曲','yuanqu','','[]','心故事。',124,'元曲/yuanqu.json','["心故事。", "往常时花笺写恨，红叶题诗，都做了风中飞絮，水上浮萍。", "痛煞煞玉连环掂的瑕疵，碜可可锦回文揉的参差。", "瘦廉纤对妆奁金粉慵施，愁荏苒绣房中拈针慵使，病恹渐锦筝ㄐ雁柱慵支。", "念兹，对此。", "匆匆岁月三之二，恰初三，早初四。", "呖呖风前孤雁儿，感起我一弄儿嗟咨。"]'),
('yuanqu-5617','黄钟尾声・雁儿，你写西风曲似苍颉字，对南浦愁如宋玉词。恰春归，早','贯云石','元','元曲','yuanqu','','[]','秋至，多寒温，少传示。',56,'元曲/yuanqu.json','["秋至，多寒温，少传示。", "恼人肠，聒人耳，碎人心，堕人志。", "雁儿，直被你撺掇出无限相思，偏怎生不寄俺有情分故人书半纸。"]'),
('yuanqu-5618','小张屠焚儿救母・仙吕/端正好','无名氏','元','元曲','yuanqu','','[]','我则待积阴功，他则待贪财物。',45,'元曲/yuanqu.json','["我则待积阴功，他则待贪财物。", "咱两个利名心水火不同炉，全不肯施财周济贫民苦，无半点儿慈悲处。"]'),
('yuanqu-5619','小张屠焚儿救母・幺篇','无名氏','元','元曲','yuanqu','','[]','便是有那金银垛至北斗待何如？当日鲁子敬谒周瑜，郭原真访亚大。',75,'元曲/yuanqu.json','["便是有那金银垛至北斗待何如？当日鲁子敬谒周瑜，郭原真访亚大。", "将一领新棉袄，你道是旧衣服。", "你二升米，看承做两斛珠。", "不由我心劳攘，意踌躇，好教我心忙怎语。"]'),
('yuanqu-5620','小张屠焚儿救母・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','母亲病在膏盲，你孩儿仰天悲怆，添惆怅。',37,'元曲/yuanqu.json','["母亲病在膏盲，你孩儿仰天悲怆，添惆怅。", "母亲受半世孤孀，却怎生越划地无承望。"]'),
('yuanqu-5621','小张屠焚儿救母・混江龙','无名氏','元','元曲','yuanqu','','[]','别无甚倚仗，受孤孀耽疾病受凄凉。',121,'元曲/yuanqu.json','["别无甚倚仗，受孤孀耽疾病受凄凉。", "心劳意攘，腹热肠慌。", "忍冻饿谁怜儿命蹇，守孤贫争敢母亲忘。", "常则是半抄儿活计，一合儿糇粮。", "看看至死，不久身亡。", "遇不收时月，饥俭年光。", "母亲眼中泪不离了枕席边，你孩儿腹中愁常潜在眉尖上。", "都不到一时半刻，寻思到百计千方。"]'),
('yuanqu-5622','小张屠焚儿救母・油葫芦','无名氏','元','元曲','yuanqu','','[]','(云)大嫂，你学几个古人，(唱)孟氏贤达有义方，夫姓梁，常则是荆钗布袄守寒窗。',102,'元曲/yuanqu.json','["(云)大嫂，你学几个古人，(唱)孟氏贤达有义方，夫姓梁，常则是荆钗布袄守寒窗。", "为夫的，文章冠世诗书广，为妻的孝廉仁义名真响。", "母亲行时时亲拜复，勤勤的厮问当。", "便有志诚心，无半点儿虚诳。", "常则是朝侍奉，暮煎汤。"]'),
('yuanqu-5623','小张屠焚儿救母・天下乐','无名氏','元','元曲','yuanqu','','[]','谁不待举案齐眉学孟光，怕不待开张，那里取升合粮？与人家打勤劳做生活有甚妨？怕不待时时的杀个猪，勤勤的宰个羊，觅几文邓通钱将我娘侍养。',66,'元曲/yuanqu.json','["谁不待举案齐眉学孟光，怕不待开张，那里取升合粮？与人家打勤劳做生活有甚妨？怕不待时时的杀个猪，勤勤的宰个羊，觅几文邓通钱将我娘侍养。"]'),
('yuanqu-5624','小张屠焚儿救母・那吒令','无名氏','元','元曲','yuanqu','','[]','住孤村小庄，无亲族当房。',51,'元曲/yuanqu.json','["住孤村小庄，无亲族当房。", "若母亲命亡，天那！谁人觑当。", "大嫂，你学取些贤孝心，我有宽宏量，休学那忤逆婆娘。"]'),
('yuanqu-5625','小张屠焚儿救母・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','带头面插金装，穿绫罗好衣裳，出来的毁遍尊亲，骂遍街坊。',50,'元曲/yuanqu.json','["带头面插金装，穿绫罗好衣裳，出来的毁遍尊亲，骂遍街坊。", "你学那哭长城送寒衣孟姜，休学那无廉耻盗果京娘。"]'),
('yuanqu-5626','小张屠焚儿救母・寄生草','无名氏','元','元曲','yuanqu','','[]','我虽不读《论》《孟》篇，多闻孝义章。',64,'元曲/yuanqu.json','["我虽不读《论》《孟》篇，多闻孝义章。", "舜子孝母天将养，郭巨埋子天恩降，孟宗哭竹天垂象。", "王祥卧鱼标写在史书中，丁兰刻木图画在丹青上。"]'),
('yuanqu-5627','小张屠焚儿救母・醉扶归','无名氏','元','元曲','yuanqu','','[]','卖弄他指下明看读广，止不过《宣明论》、《瑞竹堂》。',76,'元曲/yuanqu.json','["卖弄他指下明看读广，止不过《宣明论》、《瑞竹堂》。", "通圣散、青龙丸、白虎汤，怎莫这般药直银七两？量这个张屠户朝无夜粮。", "他可怒从心上一起，可见老母亲病着床。"]'),
('yuanqu-5628','小张屠焚儿救母・金盏儿','无名氏','元','元曲','yuanqu','','[]','朱砂面有容光，这物色淡微黄。',70,'元曲/yuanqu.json','["朱砂面有容光，这物色淡微黄。", "他那里咒连天誓说道无虚诳，恨不得手拈疾病便离床。", "愿母亲三焦和肺腹，五脏润肝畅。", "可怜见俺忤逆子，则怕妨杀俺七十娘。"]'),
('yuanqu-5629','小张屠焚儿救母・后庭花','无名氏','元','元曲','yuanqu','','[]','我这里望东岳圣帝方，祝神明心内想。',79,'元曲/yuanqu.json','["我这里望东岳圣帝方，祝神明心内想。", "则为我生身母三熊病，许下喜孙儿做一炷香。", "我这里过茶汤，愿母亲通身舒畅。", "汗溶溶如水一江，参似冰凉。", "面溶溶有喜光，笑孜孜亲问当。"]'),
('yuanqu-5630','小张屠焚儿救母・青哥儿','无名氏','元','元曲','yuanqu','','[]','病可却便是平生、平生模样，往日、往日形像。',80,'元曲/yuanqu.json','["病可却便是平生、平生模样，往日、往日形像。", "常言道孝顺心是人间海上方。", "每日家告遍街坊，谁肯惭惶？仰告穹苍，许下明香，儿做神羊。", "谁想道舍死回生便离床，兀的是天将傍。"]'),
('yuanqu-5631','小张屠焚儿救母・越调/斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','青云天宫千重，占有峰峦万朵。',73,'元曲/yuanqu.json','["青云天宫千重，占有峰峦万朵。", "明晃晃金碧琉璃，高耸耸楼台殿阁。", "王孙每宝马金鞍，士女每香车绮罗。", "正遇着春昼暄，丽日和。", "袅春风绿柳如烟，含夜雨桃红似火。"]'),
('yuanqu-5632','小张屠焚儿救母・紫花儿序','无名氏','元','元曲','yuanqu','','[]','闹清明莺声婉啭，荡花枝蝶翅蹁跹，舞东风剪尾娑婆。',75,'元曲/yuanqu.json','["闹清明莺声婉啭，荡花枝蝶翅蹁跹，舞东风剪尾娑婆。", "你看那车尘马足，作戏敲锣，聒耳笙歌，不似今年上庙的多。", "普天下名山一座，壮观着万里乾坤，永镇着百二山河。"]'),
('yuanqu-5633','小张屠焚儿救母・金蕉叶','无名氏','元','元曲','yuanqu','','[]','你去山门前潜躲，你去东廊下休来伴我。',38,'元曲/yuanqu.json','["你去山门前潜躲，你去东廊下休来伴我。", "你向松阴中权且歇波，我入三门沉吟了几合。"]'),
('yuanqu-5634','小张屠焚儿救母・调笑令','无名氏','元','元曲','yuanqu','','[]','别无甚献贺，为救俺母亲活，上圣！教张屠无奈何。',58,'元曲/yuanqu.json','["别无甚献贺，为救俺母亲活，上圣！教张屠无奈何。", "报娘恩三年乳哺恩临大，怀耽十月娘情多。", "弃儿救母绝嗣，我为亲娘暴虎冯河。"]'),
('yuanqu-5635','小张屠焚儿救母・金蕉叶','无名氏','元','元曲','yuanqu','','[]','恩养上谁人似我，孝名儿天地包罗。',35,'元曲/yuanqu.json','["恩养上谁人似我，孝名儿天地包罗。", "将亲娘煨干就湿都正过，四十年受苦奔波。"]'),
('yuanqu-5636','小张屠焚儿救母・调笑令','无名氏','元','元曲','yuanqu','','[]','为母亲疾病可，因此上许下他，便无子息待如何。',40,'元曲/yuanqu.json','["为母亲疾病可，因此上许下他，便无子息待如何。", "病未可，不须我，古人言，儿女最情多。"]'),
('yuanqu-5637','小张屠焚儿救母・鬼三台','无名氏','元','元曲','yuanqu','','[]','见神灵在空中坐，鬼使是天丁六合。',68,'元曲/yuanqu.json','["见神灵在空中坐，鬼使是天丁六合。", "炳灵公府君神像恶，速报司两鬓双皤。", "阔剑长枪排列多，有十王地府阎罗。", "上圣，金鞭指引俺孩儿，舒圣手遮罗护我。"]'),
('yuanqu-5638','小张屠焚儿救母・寨儿令','无名氏','元','元曲','yuanqu','','[]','我心恍惚，面没罗。',77,'元曲/yuanqu.json','["我心恍惚，面没罗。", "是谁人撒然惊觉我。", "则见圣像严恶，鬼似喽罗，排列的闹呵呵。", "穿红的圣体忙挪，穿青的子细评跋，穿绿的亲定夺。", "似白日里无差讹，元来是一枕梦南柯。"]'),
('yuanqu-5639','小张屠焚儿救母・鬼三台','无名氏','元','元曲','yuanqu','','[]','那里哭的声音大，到来日只少个殃人货。',79,'元曲/yuanqu.json','["那里哭的声音大，到来日只少个殃人货。", "儿女是金枷玉锁，你道他悲，理当合，你来朝也似他。", "接孩儿那人姓甚么？万人中认的是那个？你孩儿带着金钏银镯，敢远乡了神朱玉颗。"]'),
('yuanqu-5640','小张屠焚儿救母・秃厮儿','无名氏','元','元曲','yuanqu','','[]','焰腾腾无明烈火，昏惨惨宇宙屯合。',43,'元曲/yuanqu.json','["焰腾腾无明烈火，昏惨惨宇宙屯合。", "儿也！咱两个义绝恩断在这垛，人穰穰，闹呵呵，无个收罗。"]'),
('yuanqu-5641','小张屠焚儿救母・圣药王','无名氏','元','元曲','yuanqu','','[]','寻思了半晌多，当炉不选火。',52,'元曲/yuanqu.json','["寻思了半晌多，当炉不选火。", "一炷香天下愿心多，他那里泪似梭，则管里扯住我。", "报娘恩非是我风魔，火葬了小胡娑。"]'),
('yuanqu-5642','小张屠焚儿救母・尾','无名氏','元','元曲','yuanqu','','[]','两行清泪星眸中堕，我这九曲柔肠刀割。',40,'元曲/yuanqu.json','["两行清泪星眸中堕，我这九曲柔肠刀割。", "弃了个小冤家凄凉杀他，存得个老尊堂快活杀我。"]'),
('yuanqu-5643','小张屠焚儿救母・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','富和贫天地安排，使心计放钱举债，恼神灵天祸生灾。',64,'元曲/yuanqu.json','["富和贫天地安排，使心计放钱举债，恼神灵天祸生灾。", "那一个是人上人，他则待利上取利，全不想其中毒害。", "便休题苦尽甘来，利名场有成有败。"]'),
('yuanqu-5644','小张屠焚儿救母・醉春风','无名氏','元','元曲','yuanqu','','[]','他则待人满眼本钱宽，全不想得临头天地窄，明晃晃刀山一齐排，无一个改，改。',80,'元曲/yuanqu.json','["他则待人满眼本钱宽，全不想得临头天地窄，明晃晃刀山一齐排，无一个改，改。", "但有些八难三灾。", "一心斋戒，把神灵抛在九霄云外。", "(末云)奉炳灵公旨，送孝子张屠儿离了神州。"]'),
('yuanqu-5645','小张屠焚儿救母・迎仙客','无名氏','元','元曲','yuanqu','','[]','出神州十字街，下东岳摄魂台，奉圣帝速风早到来。',155,'元曲/yuanqu.json','["出神州十字街，下东岳摄魂台，奉圣帝速风早到来。", "积善的遇着祯祥，作恶的生下患害。", "哭的那厮急煎煎抹泪揉腮。", "张屠笑吟吟，醉里乾坤大。", "(外旦上，开)老身是王员外的母亲，有孩儿。", "吾儿每年三月二十八日，去大安神州做一遭买卖。", "有人来说，不见孙子神珠玉颗。", "我想王员外买卖上多有不合神道，折我这孙子。", "好去张婆婆问个信去。", "(下)。"]'),
('yuanqu-5646','小张屠焚儿救母・石榴花','无名氏','元','元曲','yuanqu','','[]','我这里入深村过长街，齐临临踏芳径步苍苔，见老娘娘低首泪盈腮。',86,'元曲/yuanqu.json','["我这里入深村过长街，齐临临踏芳径步苍苔，见老娘娘低首泪盈腮。", "莫不是张屠的奶？说不沙鬓发斑白。", "元来是济贫拔富王员外，上东岳灭罪消灾。", "据着他心平心善心宽大，何须你烧香火醮钱财。"]'),
('yuanqu-5647','小张屠焚儿救母・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','贪财的本性难移，作恶的山河易改。',66,'元曲/yuanqu.json','["贪财的本性难移，作恶的山河易改。", "这小的死卫生福，逢着善战。", "你孩儿掘着丧门遇着太岁逢着吊客，娘莫怪责。", "这孩儿牙落重生，你孩儿石沉大海。"]'),
('yuanqu-5648','小张屠焚儿救母・上小楼','无名氏','元','元曲','yuanqu','','[]','见个婆老人他那龙钟老态，恰便似这般殷勤接待。',70,'元曲/yuanqu.json','["见个婆老人他那龙钟老态，恰便似这般殷勤接待。", "你孩儿吃的醉眼横斜，醉墨淋漓，倒在长街。", "这个小婴孩，我送来，你全家宁奈，你只望着大安州磕头礼拜。"]'),
('yuanqu-5649','小张屠焚儿救母・幺篇','无名氏','元','元曲','yuanqu','','[]','一来是神明鉴戒，二来是天公眷爱。',76,'元曲/yuanqu.json','["一来是神明鉴戒，二来是天公眷爱。", "你孩儿为报娘恩，感动神灵，为母伤怀。", "你家私日日增，岁岁长，无灾无害，你一家儿否极生泰。", "(外旦云)哥，你与张屠几年朋友？。"]'),
('yuanqu-5650','小张屠焚儿救母・满庭芳','无名氏','元','元曲','yuanqu','','[]','俺两个深交数载，你张屠吃的前合后偃，东倒四歪。',93,'元曲/yuanqu.json','["俺两个深交数载，你张屠吃的前合后偃，东倒四歪。", "我惯曾出外偏怜客，违不过昆仲情怀。", "你孩儿便似病海中救出你母灾，我便是火坑中救出你儿来。", "他那里两手忙加额，我担着天来大利害，元来是天地巧安排。"]'),
('yuanqu-5651','小张屠焚儿救母・普天乐','无名氏','元','元曲','yuanqu','','[]','问从初，添惊怪，他道我头似土块，身似泥胎。',82,'元曲/yuanqu.json','["问从初，添惊怪，他道我头似土块，身似泥胎。", "支更在金殿中，听在这事在衙门外。", "牌面上书神字催香赛，拂西风满面尘埃。", "也不是张千李牌，也不跟州官县宰，这一场恰便似鬼使神差。"]'),
('yuanqu-5652','小张屠焚儿救母・快活三','无名氏','元','元曲','yuanqu','','[]','三门外大会垓，两廊下闹埃埃。',31,'元曲/yuanqu.json','["三门外大会垓，两廊下闹埃埃。", "非干运拙共财哀，则为他造恶弥天大。"]'),
('yuanqu-5653','小张屠焚儿救母・朝天子','无名氏','元','元曲','yuanqu','','[]','你那厮最歹，直恁爱财，恰待快阎王怪。',91,'元曲/yuanqu.json','["你那厮最歹，直恁爱财，恰待快阎王怪。", "你那厮损人安己惹下祸灾，(云)说与你王员外。", "再休放来生债。", "啼哭的摘胆剜心，伤情无奈，他道除死无大灾。", "炳灵公圣裁，小龙王性乖，无半时摔破了你天灵盖。"]'),
('yuanqu-5654','小张屠焚儿救母・耍孩儿','无名氏','元','元曲','yuanqu','','[]','你孩儿孝廉仁义阴功大，一炷香名扬四海。',86,'元曲/yuanqu.json','["你孩儿孝廉仁义阴功大，一炷香名扬四海。", "忠心报母世间希，美名儿动省惊台。", "孝顺名标入千秋万古忠良传，与媳妇儿立一面九烈三贞贤孝牌。", "孝名儿人都爱，姓王的祸因恶积，姓张的福已成胎。"]'),
('yuanqu-5655','小张屠焚儿救母・二煞','无名氏','元','元曲','yuanqu','','[]','张家则待要称千秋万古名，王家则待要利增百倍财，见如今鬼神嫌街坊怪。',91,'元曲/yuanqu.json','["张家则待要称千秋万古名，王家则待要利增百倍财，见如今鬼神嫌街坊怪。", "王家是非海内忧愁深，张家安乐窝中且快哉。", "到二母直拜，张婆婆道与张屠，少饮无名之酒，王婆婆说与王员外，再休贪不义之财。"]'),
('yuanqu-5656','小张屠焚儿救母・煞','无名氏','元','元曲','yuanqu','','[]','那爷爷曾抚的社稷安，补圆天地窄。',82,'元曲/yuanqu.json','["那爷爷曾抚的社稷安，补圆天地窄。", "穿一领紫罗袍，手秉着白象简，腰系着黄金带。", "那爷爷睁双怪眼乌云黑，两鬓银丝雪练白。", "那爷爷威风整神通大，断阴司能驱鬼使，判南衙不爱民财。"]'),
('yuanqu-5657','小张屠焚儿救母・尾声','无名氏','元','元曲','yuanqu','','[]','由你香焚满斗香，财排万斗财，归家还舍沿离寨，这早晚十谒朱门九不开。',55,'元曲/yuanqu.json','["由你香焚满斗香，财排万斗财，归家还舍沿离寨，这早晚十谒朱门九不开。", "一负人烟大，止不过前山后岭，休猜做大院深宅。"]'),
('yuanqu-5658','小张屠焚儿救母・煞尾','无名氏','元','元曲','yuanqu','','[]','要寻处无处寻，见来时难见来。',35,'元曲/yuanqu.json','["要寻处无处寻，见来时难见来。", "你道收藏幼子无妨碍，恰便似拾得孩儿落得摔。"]'),
('yuanqu-5659','小张屠焚儿救母・沽美酒','无名氏','元','元曲','yuanqu','','[]','迎门儿拜母亲，犹兀自醉醺醺。',56,'元曲/yuanqu.json','["迎门儿拜母亲，犹兀自醉醺醺。", "(云)孩儿交你哥哥者，连孙儿不见了。", "(唱)你似醉如呆劳梦魂，从根至本，一声声说元因。"]'),
('yuanqu-5660','小张屠焚儿救母・太平令','无名氏','元','元曲','yuanqu','','[]','想母亲病枕着床时分，你孩儿急煎煎无处安身。',53,'元曲/yuanqu.json','["想母亲病枕着床时分，你孩儿急煎煎无处安身。", "望东岳神祠一郡，格幼子喜孙儿，火焚在焦盆，是你那不孝的愚男生忿。"]'),
('yuanqu-5661','小张屠焚儿救母・雁儿落','无名氏','元','元曲','yuanqu','','[]','听说罢唬了魂，说得我半晌如痴挣。',32,'元曲/yuanqu.json','["听说罢唬了魂，说得我半晌如痴挣。", "母亲暗藏着腹内忧，打迭起心头闷。"]'),
('yuanqu-5662','小张屠焚儿救母・德胜令','无名氏','元','元曲','yuanqu','','[]','这喜孙儿把火自焚了身，正日午未黄昏。',69,'元曲/yuanqu.json','["这喜孙儿把火自焚了身，正日午未黄昏。", "皆是你媳妇严贞烈，也是你歹孩儿佯孝顺。", "我记得神灵，昨夜梦里传芳信：这小的久已后成人，到做了凌烟阁上人。"]'),
('yuanqu-5663','小张屠焚儿救母・水仙子','无名氏','元','元曲','yuanqu','','[]','莫谩天地莫谩神，远在儿孙近在身。',61,'元曲/yuanqu.json','["莫谩天地莫谩神，远在儿孙近在身。", "焚儿救母行忠信，报爷娘养育恩，劝人间爷子恩情。", "为父的行忠孝，为子的行孝顺，传与你万古留名。"]'),
('yuanqu-5664','中吕・山坡羊','陈草庵','元','元曲','yuanqu','','[]','伏低伏弱，装呆装落，是非犹自来着莫。',475,'元曲/yuanqu.json','["伏低伏弱，装呆装落，是非犹自来着莫。", "任从他，待如何？天公尚有妨农过，蚕怕雨寒苗怕火。", "阴，也是错；晴，也是错。", "身无所干，心无所患，一生不到风波岸。", "禄休干，贵休攀，功名纵得皆虚幻，浮世落花空过眼。", "官，也梦间；私，也梦间。", "林泉高攀，齑盐贫过，官囚身虑皆参破。", "富如何？贵如何？闲中自有闲中乐，天地一壶宽又阔！东，也在我；西，也在我。", "青霄有路，黄金无数，劝君万事从宽恕。", "富之余，贵也余，望将后代儿孙护，富贵不依公道取。", "儿，也受苦；孙，也受苦。", "繁华般弄，豪杰陪奉，一杯未尽笙歌送。", "恰成功，早无踪，似昨宵一枕南柯梦，人世枉将花月宠。", "春，也是空；秋，也是空。", "有钱有物，无忧无虑，赏心乐事休辜负。", "百年虚，七旬疏，饶君更比石崇富，合眼一朝天数足。", "金，也换主；银，也换主。", "风波实怕，唇舌休挂，鹤长凫短天生下。", "劝渔家，共樵家，从今莫讲贤愚话，得道多助失道寡。", "贤，也在他；愚，也在他。", "阴随阴报，阳随阳报，不以其道成家道。", "枉劬劳，不坚牢，钱财人口皆凶兆，一旦祸生福怎消？人，也散了；财，也散了。", "须教人倦，须教人怨，临危不与人方便。", "吃腥膻，着新鲜，一朝报应天公变，行止不依他在先。"]'),
('yuanqu-5665','越调・小桃红临川八景东城早春','盍西村','元','元曲','yuanqu','','[]','暮云楼阁画桥东，渐觉花心动。',432,'元曲/yuanqu.json','["暮云楼阁画桥东，渐觉花心动。", "兰麝香中看鸾凤，笑融融，半醒不醉相陪奉。", "佳宾兴浓，主人情重，合和《小桃红》。", "西园秋暮玉簪金菊露凝秋，酿出西园秀。", "烟柳新来为谁瘦？畅风流，醉归不记黄昏后。", "小糟细酒，锦堂晴昼，拚却再扶头。", "江岸水灯万家灯火闹春桥，十里光相照。", "舞凤翔鸾势绝妙，可怜宵，波间涌出蓬莱岛。", "香烟乱飘，笙歌喧闹，飞上玉楼腰。", "金堤风柳落花飞絮舞晴沙，不似都门下。", "暮折朝攀梦中怕，最堪夸，牧童渔叟偏宜夏。", "清风睡煞，淡烟难画，掩映两三家。", "客船晚烟绿云冉冉锁清湾，香彻东西岸。", "官课今年九分办，厮迫攀，渡头买得新鱼雁。", "杯盘不干，欢欣无限，忘了大家难。", "戍楼残霞戍楼残照断霞红，只有青山送。", "梨叶新来带霜重，望归鸿，归鸿也被西风弄。", "闲愁万种，旧游云梦，回首月明中。", "市桥月色玉龙高卧一天秋，宝镜青光透。", "星斗阑干雨晴后，绿悠悠，软风吹动玻璃皱。", "烟波顺流，乾坤如昼，半夜有行舟。", "莲塘雨声忽闻疏雨打新荷，有梦都惊破。", "头上闲云片时过，泛清波，兰舟饱载风流货。", "诸般小可，齐声高和，唱彻《采莲歌》。"]'),
('yuanqu-5666','双调・快活年','盍西村','元','元曲','yuanqu','','[]','闲来乘兴访渔樵，寻林泉故交。',41,'元曲/yuanqu.json','["闲来乘兴访渔樵，寻林泉故交。", "开怀畅饮两三瓢，只愿身安乐。", "笑了重还笑，沉醉倒。", "套数。"]'),
('yuanqu-5667','小梁州・珠箔银屏次第开，十二瑶阶。蔷薇洞侧牡丹台，神仙界，何必到','盍西村','元','元曲','yuanqu','','[]','天台。',3,'元曲/yuanqu.json','["天台。"]'),
('yuanqu-5668','幺・金笼鹦鹉舌头快，向人前说的明白。翠槛边，雕栏外，金沟一派，只','盍西村','元','元曲','yuanqu','','[]','许燕莺来。',5,'元曲/yuanqu.json','["许燕莺来。"]'),
('yuanqu-5669','中吕・喜春来秦定三年丙寅岁除夜，玉山舟中赋','张雨','元','元曲','yuanqu','','[]','江梅的的依茅舍，石濑溅溅漱玉沙，瓦瓯篷底送年华。',35,'元曲/yuanqu.json','["江梅的的依茅舍，石濑溅溅漱玉沙，瓦瓯篷底送年华。", "问暮鸦，何处阿戎家？。"]'),
('yuanqu-5670','双调・殿前欢杨廉夫席上有赠','张雨','元','元曲','yuanqu','','[]','小吴娃，玉盘仙掌载春霞。',53,'元曲/yuanqu.json','["小吴娃，玉盘仙掌载春霞。", "后堂绛帐重帘下，谁理琵琶？香山处士家，玉局仙人画，一刻春无价。", "老夫醉也，乌帽琼华。"]'),
('yuanqu-5671','双调・水仙子','张雨','元','元曲','yuanqu','','[]','归来重整旧生涯，潇洒柴桑处士家。',63,'元曲/yuanqu.json','["归来重整旧生涯，潇洒柴桑处士家。", "草庵儿不用高和大，会清标岂在繁华？纸糊窗，柏木榻。", "挂一幅单条画，供一枝得意花，自烧香童子煎茶。"]'),
('yuanqu-5672','鲠直张千替杀妻・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','哥哥道不敬豪门只敬礼，不羡钱财只敬德。',51,'元曲/yuanqu.json','["哥哥道不敬豪门只敬礼，不羡钱财只敬德。", "哥哥，您兄弟有句话对哥哥题，咱便似陈雷胶漆，你兄弟至死呵不相离。"]'),
('yuanqu-5673','鲠直张千替杀妻・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','杨柳晴轩，海棠深院。',25,'元曲/yuanqu.json','["杨柳晴轩，海棠深院。", "东风转，花柳争先，忙杀莺啼燕。"]'),
('yuanqu-5674','鲠直张千替杀妻・油葫芦','无名氏','元','元曲','yuanqu','','[]','嫂嫂道坟在溪桥水那边，斟量来不甚远。',96,'元曲/yuanqu.json','["嫂嫂道坟在溪桥水那边，斟量来不甚远。", "恰来到杏花庄景可人怜。", "我则见垂杨拂岸黄金线，我则见桃落处胭脂片。", "嫂嫂，这路儿更小呵！不去他大路上行，则小路儿上穿。", "骑着匹驺骅骝难把莎茵践，正是芳草地杏花天。"]'),
('yuanqu-5675','鲠直张千替杀妻・天下乐','无名氏','元','元曲','yuanqu','','[]','嫂嫂，这的是留与游人醉后眠，我想来今年，今年强似去年，若不是俺哥哥赍发有甚钱。',73,'元曲/yuanqu.json','["嫂嫂，这的是留与游人醉后眠，我想来今年，今年强似去年，若不是俺哥哥赍发有甚钱。", "人也似好觑付，亲兄弟厮顾盼。", "若不是俺哥哥嫂嫂，怎着兄弟祖坟前来祭奠。"]'),
('yuanqu-5676','鲠直张千替杀妻・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','青盛茂竹林松坞，早来到祖宗坟院。',74,'元曲/yuanqu.json','["青盛茂竹林松坞，早来到祖宗坟院。", "先挂着纸钱，躬身拜从头参见。", "忘不了哥哥重恩，小可张千，前生分缘。", "想着俺哥哥有管鲍情，关张义，聂政贤，不弃俺身微智浅。"]'),
('yuanqu-5677','鲠直张千替杀妻・元和令','无名氏','元','元曲','yuanqu','','[]','到寒食不禁烟，正清明三月天。',45,'元曲/yuanqu.json','["到寒食不禁烟，正清明三月天。", "和风习习乍晴暄，罗衣初试穿。", "为甚么嫂嫂意留连，将言、将言不言。"]'),
('yuanqu-5678','鲠直张千替杀妻・上马娇','无名氏','元','元曲','yuanqu','','[]','嫂嫂，更道是颠，更做道贤，恰便似卖俏女婵娟。',52,'元曲/yuanqu.json','["嫂嫂，更道是颠，更做道贤，恰便似卖俏女婵娟。", "(旦云了)吃的来醉醺醺将咱来缠，眼溜溜涎。", "他道是休停莫俄延。"]'),
('yuanqu-5679','鲠直张千替杀妻・游四门','无名氏','元','元曲','yuanqu','','[]','呀！不赌时搂抱在祭台边，这婆娘色胆大如天。',46,'元曲/yuanqu.json','["呀！不赌时搂抱在祭台边，这婆娘色胆大如天。", "恰不怕柳外人瞧见。", "又不是颠，往日贤，都做了鬼胡延。"]'),
('yuanqu-5680','鲠直张千替杀妻・胜葫芦','无名氏','元','元曲','yuanqu','','[]','嫂嫂，休！俺哥哥往直西不到半年，想兄弟情无思念？你看路人又不离地远。',53,'元曲/yuanqu.json','["嫂嫂，休！俺哥哥往直西不到半年，想兄弟情无思念？你看路人又不离地远。", "你待为非作歹，瞒心昧己，终久是不牢坚。"]'),
('yuanqu-5681','鲠直张千替杀妻・幺篇','无名氏','元','元曲','yuanqu','','[]','嫂嫂道瓦罐终须不离井边，你未醉后人在言。',80,'元曲/yuanqu.json','["嫂嫂道瓦罐终须不离井边，你未醉后人在言。", "你气的我手儿脚儿滴修都速战。", "莫动，不，嫂嫂和俺哥哥是几年夫妻？(旦云)二十年夫妻。", "又不想同衾结发，情深义重，夫乃妇之天。"]'),
('yuanqu-5682','鲠直张千替杀妻・后庭花','无名氏','元','元曲','yuanqu','','[]','你休要犯王条成罪愆，则索辨人伦依正典。',73,'元曲/yuanqu.json','["你休要犯王条成罪愆，则索辨人伦依正典。", "不听见九烈三贞女，三从四德贤。", "今日个到坟园，祖宗如见。", "有灵魂在墓前，你狂张不怕天。", "胡寻思一点，留歹名百世传。"]'),
('yuanqu-5683','鲠直张千替杀妻・尾声','无名氏','元','元曲','yuanqu','','[]','我这一腔铁石心，不比你趁浪风尘怨。',120,'元曲/yuanqu.json','["我这一腔铁石心，不比你趁浪风尘怨。", "我虽是无歹心胡做，若这句我这句话合该一千，须我不得将闲话儿展。", "嫂嫂，你着马先行。", "我空说在骏马之前。", "嫂嫂将着紫藤鞭，催动缰辕，赚的回你家解了我冤。", "你倚仗着有金有钱，欺负俺哥哥无亲无眷，不曾见浪包娄养汉倒陪钱。"]'),
('yuanqu-5684','鲠直张千替杀妻・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','撇罢了腹中愁。',54,'元曲/yuanqu.json','["撇罢了腹中愁。", "则今打迭起心头闷，嫂嫂也从今后休恋别人。", "(旦云了)若是俺哥哥一一从头问，看我数说你一会无淹润。"]'),
('yuanqu-5685','鲠直张千替杀妻・滚绣球','无名氏','元','元曲','yuanqu','','[]','俺哥哥恰路上受苦辛，干事忒谨勤，俺哥哥惹近远也，刚道了往来劳困，(外云了)(唱)哥哥鞍马上远路风尘。',133,'元曲/yuanqu.json','["俺哥哥恰路上受苦辛，干事忒谨勤，俺哥哥惹近远也，刚道了往来劳困，(外云了)(唱)哥哥鞍马上远路风尘。", "(外问了)母亲又无甚证候，咫尺有些老忘浑，托赖着俺哥哥福阴，那里有半星儿疾病缠身。", "(外问了)嫂嫂母亲行更加十分孝，俺嫂嫂近日来兄弟行街崇添一倍儿亲，看我说你一会叮咛。"]'),
('yuanqu-5686','鲠直张千替杀妻・倘秀才','无名氏','元','元曲','yuanqu','','[]','当日哥哥不曾见半点儿文墨，与我许多资本。',89,'元曲/yuanqu.json','["当日哥哥不曾见半点儿文墨，与我许多资本。", "哥哥请吃兄弟这一盏酒，除外别无甚顺。", "想哥哥山海也似恩临几时尽？且休说放钱的庞居士，更压着养剑客的孟尝君，那里有俺哥哥意分。", "(外讨酒饮了)。"]'),
('yuanqu-5687','鲠直张千替杀妻・滚绣球','无名氏','元','元曲','yuanqu','','[]','酒行了十数巡，连饮了八九尊，(旦教劝员外酒科)嫂嫂，你看俺哥哥不抬头呵，又兼那身困，则为你吓杀我也七世魔君。',157,'元曲/yuanqu.json','["酒行了十数巡，连饮了八九尊，(旦教劝员外酒科)嫂嫂，你看俺哥哥不抬头呵，又兼那身困，则为你吓杀我也七世魔君。", "早则阳台有故人，罗帏中会雨云，不如背地里暗传芳信。", "(外唱曲科)哎！你个楚襄王，百忙里唱甚末白雪阳春？(外醉睡科)我这酒肠宽宋玉才挪动脚，(末辞科，旦拦住科)被你这色胆如巫蛾，你则末拦住了门？唬的我无处藏身。"]'),
('yuanqu-5688','鲠直张千替杀妻・倘秀才','无名氏','元','元曲','yuanqu','','[]','嫂嫂，我往常时草鞋兜不住脚根，到如今旧头巾遮不了顶门，却甚末白马红缨彩色新？恰不道壁间还有耳，窗外岂无人，你待要怎生？。',60,'元曲/yuanqu.json','["嫂嫂，我往常时草鞋兜不住脚根，到如今旧头巾遮不了顶门，却甚末白马红缨彩色新？恰不道壁间还有耳，窗外岂无人，你待要怎生？。"]'),
('yuanqu-5689','鲠直张千替杀妻・滚绣球','无名氏','元','元曲','yuanqu','','[]','我这里忙倒退，越赶得我紧，(旦云了)你是妇人家絮叨叨不嫌口困。',126,'元曲/yuanqu.json','["我这里忙倒退，越赶得我紧，(旦云了)你是妇人家絮叨叨不嫌口困。", "(旦云了)这埚儿比不得你祭台边唬鬼瞒神。", "知他是你风魔，我沙村。", "嫂嫂不争你这般呵送的我有家难奔，严白里更待要燕尔新婚。", "(旦云了)不争二更前后成连理，俺哥哥知道呵敢九伯风魔哎吊了脊筋，好是伤情。"]'),
('yuanqu-5690','鲠直张千替杀妻・倘秀才','无名氏','元','元曲','yuanqu','','[]','俺哥哥赍发我呵金与银，我今日杀兄长呵，却不知恩报恩，却不知自己贪杯惜醉人。',68,'元曲/yuanqu.json','["俺哥哥赍发我呵金与银，我今日杀兄长呵，却不知恩报恩，却不知自己贪杯惜醉人。", "(旦云了)我则理会庞涓刖了孙膑，几曾见张仪冻杀苏秦，好教自嗔。"]'),
('yuanqu-5691','鲠直张千替杀妻・滚绣球','无名氏','元','元曲','yuanqu','','[]','这婆娘外相儿贞，就里狠，纵然面搽红粉，是一个油髟。',25,'元曲/yuanqu.json','["这婆娘外相儿贞，就里狠，纵然面搽红粉，是一个油髟。"]'),
('yuanqu-5692','鲠直张千替杀妻・叨叨令','无名氏','元','元曲','yuanqu','','[]','俺哥哥汤风犯雪金兰分，你兄弟酒里淘真性。',113,'元曲/yuanqu.json','["俺哥哥汤风犯雪金兰分，你兄弟酒里淘真性。", "我则理会得哥哥赍发张屠闲。", "我那里重色轻君子，那里有海棠娇江梅韵。", "(末持刀揪旦科)(旦云)却怎生杀我？(末云)我剪背杀你。", "大古里孟姜女不杀了要怎末哥？孟姜女不杀了要怎末哥？一朝马死黄金尽。"]'),
('yuanqu-5693','鲠直张千替杀妻・醉春风','无名氏','元','元曲','yuanqu','','[]','他不想夫妇恩重如山，待将一个亲男儿谋算了。',64,'元曲/yuanqu.json','["他不想夫妇恩重如山，待将一个亲男儿谋算了。", "珠英断臂去留名，似这妇人的少，少。", "我因此上手揽定青丝，杀坏了不中淫妇，我待学知心管鲍。"]'),
('yuanqu-5694','鲠直张千替杀妻・快活三','无名氏','元','元曲','yuanqu','','[]','杀人贼有下落，杀人贼省归着。',34,'元曲/yuanqu.json','["杀人贼有下落，杀人贼省归着。", "杀人贼今日有根苗，母亲，我不说谁知道！。"]'),
('yuanqu-5695','鲠直张千替杀妻・朝天子','无名氏','元','元曲','yuanqu','','[]','母亲呵寿高，您儿呵不肖，不想咱人死呵天知道。',97,'元曲/yuanqu.json','["母亲呵寿高，您儿呵不肖，不想咱人死呵天知道。", "母亲啼天哭地泪流交，您儿不曾将山海恩临报。", "我这里苦痛哮啕，捶胸高叫，母亲你指望养儿来防备老。", "(母亲云了)不争你儿不招，把哥哥送了，枉惹得普天下英雄笑。"]'),
('yuanqu-5696','鲠直张千替杀妻・上小楼','无名氏','元','元曲','yuanqu','','[]','我这里孜孜觑了，唬的扑扑心跳。',61,'元曲/yuanqu.json','["我这里孜孜觑了，唬的扑扑心跳。", "好教我战战兢兢，滴修都速，魄散魂消。", "是俺哥哥，坐死牢，折到了他当时容貌，我是铁石人暗伤怀抱。"]'),
('yuanqu-5697','鲠直张千替杀妻・幺篇','无名氏','元','元曲','yuanqu','','[]','他那里吃一杖，则如剁一刀。',59,'元曲/yuanqu.json','["他那里吃一杖，则如剁一刀。", "我这里腹热心慌，手忙脚乱，皮战身摇。", "往常时那威风，那势耀，人中才貌，我这里向官人行怎生哀告。"]'),
('yuanqu-5698','鲠直张千替杀妻・满庭芳','无名氏','元','元曲','yuanqu','','[]','杀人贼我招，相公把干连人放了，犯法的难饶。',79,'元曲/yuanqu.json','["杀人贼我招，相公把干连人放了，犯法的难饶。", "俺哥哥山海也似恩未报，怎肯道善与人交。", "那婆娘罪恶到，官人上难学，空养着家中俏。", "我根前欲待私情暗约，那婆娘笑里暗藏刀。"]'),
('yuanqu-5699','鲠直张千替杀妻・石榴花','无名氏','元','元曲','yuanqu','','[]','俺本是提刀屠，番做了知心交，论仁义，有谁学。',95,'元曲/yuanqu.json','["俺本是提刀屠，番做了知心交，论仁义，有谁学。", "俺哥哥索钱去了，离别到半载之遥，那婆娘打扮来便似女猱，全不似好人家苗条。", "上坟处说不尽乔为作，那里怕野外荒郊。", "他从早晨间缠到日头落，回来明月上花梢。"]'),
('yuanqu-5700','鲠直张千替杀妻・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','我若背义忘恩，早和他私情暗约。',71,'元曲/yuanqu.json','["我若背义忘恩，早和他私情暗约。", "后来俺哥哥来家，夜深吃的来醉倒。", "呀！婆娘待把俺哥哥所算了，被我赚得他手内刀。", "想俺哥哥昆仲情深，因此上把婆娘坏了。"]'),
('yuanqu-5701','鲠直张千替杀妻・十二月','无名氏','元','元曲','yuanqu','','[]','便怕甚担烦受恼，判了个无处归着。',48,'元曲/yuanqu.json','["便怕甚担烦受恼，判了个无处归着。", "俺哥哥从来软弱，几曾见犯法违条？惜不得家亲年老，好教我苦痛哮啕。"]'),
('yuanqu-5702','鲠直张千替杀妻・尧民歌','无名氏','元','元曲','yuanqu','','[]','哥哥，你养侍白头娘我在死囚牢，常言道舌是斩身刀。',64,'元曲/yuanqu.json','["哥哥，你养侍白头娘我在死囚牢，常言道舌是斩身刀。", "当年祸福不相交，今日官门有着落。", "哥哥休焦，把这个躯好观着，是必休教俺残疾娘知道。"]'),
('yuanqu-5703','鲠直张千替杀妻・耍孩儿','无名氏','元','元曲','yuanqu','','[]','我往常时看别人笞杖徒流绞，今日个轮到我绷扒吊拷。',95,'元曲/yuanqu.json','["我往常时看别人笞杖徒流绞，今日个轮到我绷扒吊拷。", "指望咱弟兄情，如陈雷胶漆有谁学，登时间瓦解冰消。", "当初一年结义知心友，谁想咱半路里番腾做刎颈交？泪不住腮边落，眼见的一刀两段，知他是今日明朝？。"]'),
('yuanqu-5704','鲠直张千替杀妻・三煞','无名氏','元','元曲','yuanqu','','[]','母亲第一来残疾多，第二来年纪老。',63,'元曲/yuanqu.json','["母亲第一来残疾多，第二来年纪老。", "常有些不快长安乐，怕有些时截取匹整布绢，无钱时打我条孝系腰。", "泪不住行行落，哀哀父母，生我劬劳。"]'),
('yuanqu-5705','鲠直张千替杀妻・四煞','无名氏','元','元曲','yuanqu','','[]','哥哥，咱为兄弟非关今世亲，皆因前缘前世报。',73,'元曲/yuanqu.json','["哥哥，咱为兄弟非关今世亲，皆因前缘前世报。", "怎着我一心想哥哥思念伏侍到老，谁想半路里这妇人把哥哥折算了。", "不由心焦躁，因此上着命身亡，便死呵并无悔懊。"]'),
('yuanqu-5706','鲠直张千替杀妻・尾声','无名氏','元','元曲','yuanqu','','[]','哥哥，我死去程途多，回来的路儿少。',44,'元曲/yuanqu.json','["哥哥，我死去程途多，回来的路儿少。", "俺哥哥行半星儿恩义不曾报，我有七十岁的亲娘侍奉不到老。"]'),
('yuanqu-5707','鲠直张千替杀妻・双调/新水令','无名氏','元','元曲','yuanqu','','[]','从来猛虎不吃傍窝食，送的我死无葬身之地。',53,'元曲/yuanqu.json','["从来猛虎不吃傍窝食，送的我死无葬身之地。", "则为知心友番做杀人贼，普天下拜义亲戚，则你口快心直，休似我忒仁义。"]'),
('yuanqu-5708','鲠直张千替杀妻・夜行船','无名氏','元','元曲','yuanqu','','[]','哥哥慈悲，盛把兄弟相周急。',42,'元曲/yuanqu.json','["哥哥慈悲，盛把兄弟相周急。", "如今谢哥哥将来的酒和食，这的长离饭永别杯，碜可可我尝酒味。"]'),
('yuanqu-5709','鲠直张千替杀妻・雁儿落','无名氏','元','元曲','yuanqu','','[]','哥哥，万剐我不后悔，这里便死呵无招对。',32,'元曲/yuanqu.json','["哥哥，万剐我不后悔，这里便死呵无招对。", "常学着仗义心，四海皆兄弟。"]'),
('yuanqu-5710','鲠直张千替杀妻・得胜令','无名氏','元','元曲','yuanqu','','[]','我死呵记相识，你从今好将息。',100,'元曲/yuanqu.json','["我死呵记相识，你从今好将息。", "与我干取些穷活计，休惹人闲是非。", "你非。", "你再休贪杯，见放着傍州例。", "你若求妻，(云)常言道丑妇家中宝，休贪他人才精精细细，伶伶俐俐，能言快语，不中。", "(外云了)娶一个端方稳重的。"]'),
('yuanqu-5711','鲠直张千替杀妻・落梅风','无名氏','元','元曲','yuanqu','','[]','脑背后，高声叫起，唬的我魂离体，死无葬身之地。',49,'元曲/yuanqu.json','["脑背后，高声叫起，唬的我魂离体，死无葬身之地。", "母亲道认义来的哥哥有债回的礼，母亲也早难道养军千日。"]'),
('yuanqu-5712','鲠直张千替杀妻・甜水令','无名氏','元','元曲','yuanqu','','[]','我则见街坊邻里，大的小的，啼天哭地，见了我并无一个感叹伤悲。',54,'元曲/yuanqu.json','["我则见街坊邻里，大的小的，啼天哭地，见了我并无一个感叹伤悲。", "他道不爱娘，替人偿命，生分忤逆，丑名儿万代人知。"]'),
('yuanqu-5713','鲠直张千替杀妻・折桂令','无名氏','元','元曲','yuanqu','','[]','哎，母亲！早则无指望绿鬓斑衣，母亲那里有九病十残，腰屈头低。',84,'元曲/yuanqu.json','["哎，母亲！早则无指望绿鬓斑衣，母亲那里有九病十残，腰屈头低。", "告哥哥且慢休摧，省可里后推前推。", "半霎儿午时三刻，弟兄子母别离，哭哭啼啼，切切悲悲。", "百忙里地惨天昏，雾锁云迷。"]'),
('yuanqu-5714','鲠直张千替杀妻・水仙子','无名氏','元','元曲','yuanqu','','[]','一灵儿相伴着野云飞，则听得脑背后何人高叫起，是哥哥共母亲傍边立。',72,'元曲/yuanqu.json','["一灵儿相伴着野云飞，则听得脑背后何人高叫起，是哥哥共母亲傍边立。", "我问你怎生来到这里，险送了家有贤妻。", "杀嫂索偿命，宜镌刎颈碑，我将好名儿万古标题。"]'),
('yuanqu-5715','南吕・一枝花秋夜闻筝','班惟志','元','元曲','yuanqu','','[]','透疏帘风摇杨柳阴，泻长空月转梧桐影。',73,'元曲/yuanqu.json','["透疏帘风摇杨柳阴，泻长空月转梧桐影。", "冷雕盘香销金兽火，咽铜龙漏滴玉壶冰。", "何处银筝？声嘹呖云霄应，逐轻风过短棂。", "耳才闻天上《仙韶》，身疑在人间胜境。"]'),
('yuanqu-5716','梁州・恰便似溅石窟寒泉乱涌，集瑶台鸾凤和鸣，走金盘乱撒骊珠迸。嘶','班惟志','元','元曲','yuanqu','','[]','风骏偃，潜沼鱼惊。',105,'元曲/yuanqu.json','["风骏偃，潜沼鱼惊。", "天边雁落，树梢云停。", "早则是字样分明，更那堪音律关情！凄凉比汉昭君塞上琵琶，清韵如王子乔风前玉笙，修扬似张君瑞月下琴声。", "再听，愈惊。", "叮咛一曲《阳关令》，感离愁，动别兴。", "万事萦怀百样增，一洗尘清。"]'),
('yuanqu-5717','尾・他那里轻笼纤指冰弦应，俺这里谩写花笺锦字迎，越感起文园少年病。','班惟志','元','元曲','yuanqu','','[]','是谁家玉卿，只恁般可憎，唤的人一枕胡蝶梦儿醒！。',24,'元曲/yuanqu.json','["是谁家玉卿，只恁般可憎，唤的人一枕胡蝶梦儿醒！。"]'),
('yuanqu-5718','仙吕・醉中天嘲人右手三指','赵彦晖','元','元曲','yuanqu','','[]','把盏难舒手，施礼怎合十？亏他朝朝洗面皮，早是刚拿管笔。',106,'元曲/yuanqu.json','["把盏难舒手，施礼怎合十？亏他朝朝洗面皮，早是刚拿管笔。", "便有那举鼎拔山的气力，诸般儿都会，怎拿他鞭简丫锤？把盏难舒手，学舞不风流。", "与你架银筝怎地ㄐ？难挽衫儿袖。", "他媳妇问他索休，别无甚圆就，到官司打与一个拳头。", "套数。"]'),
('yuanqu-5719','混江龙・长想着少年时候，拈花摘叶甚风流。见了些春风谢馆，夜月秦楼','赵彦晖','元','元曲','yuanqu','','[]','马上抱鸡三市斗，袖中携剑五陵游。',33,'元曲/yuanqu.json','["马上抱鸡三市斗，袖中携剑五陵游。", "八个字非虚谬：玲珑剔透，软款温柔。"]'),
('yuanqu-5720','油葫芦・一世疏狂一笔勾，从今后都罢手，一场恩爱变为仇。赤紧的红裙','赵彦晖','元','元曲','yuanqu','','[]','不解嘲风口，以此上青衫紧退揉花手。',48,'元曲/yuanqu.json','["不解嘲风口，以此上青衫紧退揉花手。", "想着眼底情，眉角愁。", "则管里云来雨去空<辶它>逗，终不见下场头。"]'),
('yuanqu-5721','天下乐・只被你干赚得潘郎两鬓秋。想着你恩情，也不是永久，恰便似风','赵彦晖','元','元曲','yuanqu','','[]','中落花水上沤。',36,'元曲/yuanqu.json','["中落花水上沤。", "我恰待踏折他花套竿，撞出锦<囗贵>头，早是咱千自在百自由。"]'),
('yuanqu-5722','那吒令・想当初您爱我时，剪青丝半纽。想当初敬您时，赠吟词一首。您','赵彦晖','元','元曲','yuanqu','','[]','如今弃俺也，断金钗两头。',32,'元曲/yuanqu.json','["如今弃俺也，断金钗两头。", "想着您月底盟，星前咒，则怕你悔去也娇羞。"]'),
('yuanqu-5723','鹊踏枝・俺如今志难酬，和俺不相投。误了俺雁塔题名。虎榜名留。有一','赵彦晖','元','元曲','yuanqu','','[]','日博得五花诰在手，则怕你消不得粉面油头。',20,'元曲/yuanqu.json','["日博得五花诰在手，则怕你消不得粉面油头。"]'),
('yuanqu-5724','寄生草・俺如今时间困，目下忧。三尺剑扫荡红尘垢，万言策补尽乾坤漏，','赵彦晖','元','元曲','yuanqu','','[]','五言诗夺尽江山秀。',33,'元曲/yuanqu.json','["五言诗夺尽江山秀。", "若是柳耆卿剥得个紫袍新，你便是谢天香不避黄齑臭。"]'),
('yuanqu-5725','混江龙・他若是含情一笑，朱唇一颗嵌樱桃。梨花玉体，杨柳纤腰。眉黛','赵彦晖','元','元曲','yuanqu','','[]','春山娇滴滴，眼波秋水绿淘淘。',68,'元曲/yuanqu.json','["春山娇滴滴，眼波秋水绿淘淘。", "可观可看，宜喜宜嗔。", "堪怜堪爱，难画难描。", "拨银筝音吕韵悠扬，唱阳春白雪依腔调。", "你便有千金买笑，怎能够一刻春宵。"]'),
('yuanqu-5726','油葫芦・喜遇得樽席上猛见了，更那堪情性好，言谈语话那清标。你看那','赵彦晖','元','元曲','yuanqu','','[]','聪明伶俐诸般妙，更那堪续麻道字无差错。',48,'元曲/yuanqu.json','["聪明伶俐诸般妙，更那堪续麻道字无差错。", "生的来花样娇，柳样柔。", "知今博古通三教，铁石人一见了也魂销。"]'),
('yuanqu-5727','天下乐・怎能够玉树同栖翡翠巢？无福的难也波消。自暗约，用心儿访寻','赵彦晖','元','元曲','yuanqu','','[]','月下老。',32,'元曲/yuanqu.json','["月下老。", "者莫你能会弹能会歌，能会绣能会描，怎生来少前程无下梢？。"]'),
('yuanqu-5728','那吒令・离情空懊恼，我魂劳梦劳；缘薄命薄，看明朝后朝。我劝你断肠','赵彦晖','元','元曲','yuanqu','','[]','籍上除了姓名，姻缘簿上寻个着落，一星星记在心苗。',24,'元曲/yuanqu.json','["籍上除了姓名，姻缘簿上寻个着落，一星星记在心苗。"]'),
('yuanqu-5729','鹊踏枝・我与你自量度，是评跋。你若听琴，我便题桥。趁青春年纪儿幼','赵彦晖','元','元曲','yuanqu','','[]','小，休辜负好前程月夜花朝。',13,'元曲/yuanqu.json','["小，休辜负好前程月夜花朝。"]'),
('yuanqu-5730','寄生草・相思病何年尽？姻缘簿甚日了？你看他知轻知重知分晓，不能够','赵彦晖','元','元曲','yuanqu','','[]','同行同坐同欢笑，到教我添愁添闷添烦恼。',44,'元曲/yuanqu.json','["同行同坐同欢笑，到教我添愁添闷添烦恼。", "怎能够喜孜孜花下燕莺期？几时得笑吟吟春日鸳鸯效？。"]'),
('yuanqu-5731','六幺序・眼前面人千里，耳边厢音信杳，隔三千弱水迢迢。闷恹恹鬼病难','赵彦晖','元','元曲','yuanqu','','[]','熬，意迟迟情思心焦。',60,'元曲/yuanqu.json','["熬，意迟迟情思心焦。", "桃源洞不见分毫，焰腾腾烈火烧袄庙，白茫茫水淹蓝桥。", "莫不是我今生撅着相思窖？好教我行眠立盹，梦断魂劳。"]'),
('yuanqu-5732','尾声・准备着花烛洞房春，安排下夜月笙歌笑，那时节喜喜欢欢宴乐。地','赵彦晖','元','元曲','yuanqu','','[]','久天长成配偶，一世儿永远坚牢。',64,'元曲/yuanqu.json','["久天长成配偶，一世儿永远坚牢。", "画堂高怕是么暮暮朝朝，则学那连理树、合欢带、比翼鸟。", "宝炉香渐烧，银台灯高照，成就了碧桃花下凤鸾交。"]'),
('yuanqu-5733','南吕・一枝花嘲僧','赵彦晖','元','元曲','yuanqu','','[]','七宝罗汉身，八难观音像。',68,'元曲/yuanqu.json','["七宝罗汉身，八难观音像。", "玉楼巢翡翠，谁教你金殿锁鸳鸯？箫寺里蝶乱蜂狂，玉溪馆青楼巷，缘得五台山傅粉郎。", "小和尚久等莺娘，老亚仙风魔了志广。"]'),
('yuanqu-5734','梁州・常则是金斗郡双生和小卿，几曾见丽春园苏氏和都刚？被个老妖精','赵彦晖','元','元曲','yuanqu','','[]','狐媚了唐三藏。',122,'元曲/yuanqu.json','["狐媚了唐三藏。", "一个供佛的柳翠，伴着个好色东堂。", "钟楼鼓阁，便做了待月西厢。", "丑禅师宠定个天香，笑吟吟携手相将。", "风帏中路柳参禅，鸳帐底烟花听讲，看门儿亏杀金刚。", "暗想，这场。", "出家儿招揽乔公状，你也不是清静僧，真乃是莽和尚。", "当了袈裟做一场，岂怕人声扬？。"]'),
('yuanqu-5735','尾・十年功业难修养，取得个年老妖精复落娼，卧兔当来受灾障，常把三','赵彦晖','元','元曲','yuanqu','','[]','门紧关上。',27,'元曲/yuanqu.json','["门紧关上。", "那妮子僧房中叫，反教你削了发的耆卿后院里攘。"]'),
('yuanqu-5736','南吕・一枝花','赵彦晖','元','元曲','yuanqu','','[]','熬煎碎窃玉心，辜负损偷香胆。',63,'元曲/yuanqu.json','["熬煎碎窃玉心，辜负损偷香胆。", "好姻缘成间阻，乔风月畅难担。", "恩爱相搀，连理枝和根砍，并头莲伏地芟。", "淹蓝桥波浪涨漫，烧袄庙风烟焰惨。"]'),
('yuanqu-5737','尾・那其间亲和疏自有知音鉴，好共歹从教晓事的谈，锦信也似前程怎摇','赵彦晖','元','元曲','yuanqu','','[]','你早自信咱咱，咱咱，那从小的争锋按下的胆。',21,'元曲/yuanqu.json','["你早自信咱咱，咱咱，那从小的争锋按下的胆。"]'),
('yuanqu-5738','仙吕・一半儿','宋方壶','元','元曲','yuanqu','','[]','别时容易见时难，玉减香消衣带宽。',38,'元曲/yuanqu.json','["别时容易见时难，玉减香消衣带宽。", "夜深绣户犹未拴，待他还，一半儿微开一半儿关。"]'),
('yuanqu-5739','中吕・红绣鞋阅世','宋方壶','元','元曲','yuanqu','','[]','短命的偏逢薄幸，老成的偏遇真成，无情的休想遇多情。',99,'元曲/yuanqu.json','["短命的偏逢薄幸，老成的偏遇真成，无情的休想遇多情。", "懵懂的怜瞌睡，鹘伶的惜惺惺，若要轻别人还自轻。", "客况雨潇潇一帘风劲，昏惨惨半点灯明，地炉无火拨残星。", "薄设设衾剩铁，孤另另枕如冰，我却是怎支吾今夜冷？。"]'),
('yuanqu-5740','中吕・山坡羊道情','宋方壶','元','元曲','yuanqu','','[]','布袍粗袜，山间林下，功名二字皆勾罢。',113,'元曲/yuanqu.json','["布袍粗袜，山间林下，功名二字皆勾罢。", "醉联麻，醒烹茶，竹风松月浑无价，绿绮纹楸时聚话。", "官，谁问他；民，谁问他！青山相待，白去相爱，梦不到紫罗袍共黄金带。", "一茅斋，野花开，管甚谁家兴废谁成败？陋巷箪瓢亦乐哉！贫，气不改；达，志不改。"]'),
('yuanqu-5741','商调・梧叶儿怀古','宋方壶','元','元曲','yuanqu','','[]','黄州地，赤壁矶，衰草接天涯。',34,'元曲/yuanqu.json','["黄州地，赤壁矶，衰草接天涯。", "周公瑾，曹孟德，果何为？都打入渔樵话里。"]'),
('yuanqu-5742','双调・雁儿落过得胜令闲居','宋方壶','元','元曲','yuanqu','','[]','功名梦不成，富贵心勾罢。',71,'元曲/yuanqu.json','["功名梦不成，富贵心勾罢。", "青山绿水间，茅舍疏篱下。", "广种邵平瓜，细焙玉川茶，遍插渊明柳，多栽潘令花。", "清佳，寻方外清幽话；欢恰，与亲朋闲戏耍。", "套数。"]'),
('yuanqu-5743','黄钟・醉花阴走苏卿','宋方壶','元','元曲','yuanqu','','[]','雪浪银涛大江迥，举目玻璃万顷，天际水云平。',48,'元曲/yuanqu.json','["雪浪银涛大江迥，举目玻璃万顷，天际水云平。", "浩浩澄澄，越感的人孤另。", "一叶片帆轻，直赶到金山不见影。"]'),
('yuanqu-5744','出队子・心中溪幸，意痴痴，愁转增。猛然见梵王宫得悟的老禅僧，何处','宋方壶','元','元曲','yuanqu','','[]','也金斗郡无心苏小卿，空闪下临川县多情双县令。',22,'元曲/yuanqu.json','["也金斗郡无心苏小卿，空闪下临川县多情双县令。"]'),
('yuanqu-5745','刮地风・我这里叉手躬身将礼数迎，请禅师细说叮咛。他道有一个女娉婷，','宋方壶','元','元曲','yuanqu','','[]','寺里闲踢蹬。',83,'元曲/yuanqu.json','["寺里闲踢蹬。", "他生的袅袅婷婷，阁不住的雨泪盈盈。", "愁凄凄有如痴挣，闷恹恹染成疾病，蘸霜毫回廊下壁上题名。", "猛抬头恰定睛，正是俺可意多情，走龙蛇字体儿堪人敬，他诉衷肠表志诚。"]'),
('yuanqu-5746','四门子・他道，狠毒娘硬接了冯魁的定，揣与我个恶罪名。当初实意儿守，','宋方壶','元','元曲','yuanqu','','[]','真心儿等，恰便似竹林寺有影不见形。',35,'元曲/yuanqu.json','["真心儿等，恰便似竹林寺有影不见形。", "实意儿守，真心儿等，他可便如何折证。"]'),
('yuanqu-5747','古水仙子・他、他、他，觑绝罢两泪倾，便有那九江水如何洗得清？当初','宋方壶','元','元曲','yuanqu','','[]','指雁为羹，充饥画饼，道无情却有情。',60,'元曲/yuanqu.json','["指雁为羹，充饥画饼，道无情却有情。", "我、我、我，暗暗的仔细评论，俏苏卿摔碎粉面筝，村冯魁硬对菱花镜，则俺狠毒娘有甚前程！。"]'),
('yuanqu-5748','者刺古・占天边月共星，同坐同行。对神前说誓盟，言死言生。香焚在宝','宋方壶','元','元曲','yuanqu','','[]','鼎，酒斟在玉觥。',20,'元曲/yuanqu.json','["鼎，酒斟在玉觥。", "越越的人孤另，分开燕莺。"]'),
('yuanqu-5750','节节高・碧天云净，绿波风定。银蟾皎洁，猛然见俺多情薄幸。俺两个附','宋方壶','元','元曲','yuanqu','','[]','耳言，低声语，携手行，呀！下水船如何觅影？。',22,'元曲/yuanqu.json','["耳言，低声语，携手行，呀！下水船如何觅影？。"]'),
('yuanqu-5751','尾声・说与你个冯魁耐心听：俺两个喜孜孜俏语低声，你在那蓝桥下细寻','宋方壶','元','元曲','yuanqu','','[]','思谩谩等。',5,'元曲/yuanqu.json','["思谩谩等。"]'),
('yuanqu-5752','尾・闲时节不离了花香柳影清阴里睡，闷时节则就日暖风和叶底下依，不','宋方壶','元','元曲','yuanqu','','[]','想瘦躯老人根前逞精细。',102,'元曲/yuanqu.json','["想瘦躯老人根前逞精细。", "且休说香罗袖里，桃花扇底，则怕露冷天寒恁时节悔。", "妓女自生在柳陌中，长立在花街内。", "打熬成风月胆，断送了雨云期。", "只为二字衣食，卖笑为活计。", "每日都准备，准备下些送旧迎新，安排下过从的见识。"]'),
('yuanqu-5753','梁州・有一等强风情迷魂子弟，初出帐笋嫩勤儿。起初儿待要成欢会。教','宋方壶','元','元曲','yuanqu','','[]','那厮一合儿昏撒，半霎儿著迷。',102,'元曲/yuanqu.json','["那厮一合儿昏撒，半霎儿著迷。", "典房卖舍，弃子休妻。", "逐朝价密约幽期，每日价弄盏传杯。", "一更里酒酽花浓，半夜里如鱼似水，呀！五更头财散人离。", "你东，我西。", "一番价有钞一番睡，旋打算旋伶利。", "将取孛兰数取梨，有甚希奇？。"]'),
('yuanqu-5754','尾・有钱每日同欢会，无钱的郎君好厮离，绿豆皮儿你请退！打发了这壁，','宋方壶','元','元曲','yuanqu','','[]','安排下那壁，七八下里郎君都应付得喜。',18,'元曲/yuanqu.json','["安排下那壁，七八下里郎君都应付得喜。"]'),
('yuanqu-5755','越调・斗鹌鹑送别','宋方壶','元','元曲','yuanqu','','[]','落日遥岑，淡烟远浦。',47,'元曲/yuanqu.json','["落日遥岑，淡烟远浦。", "萧寺疏钟，戍楼暮鼓。", "一叶扁舟，数声去橹那惨戚，那凄楚，恰待欢娱，顿成间阻。"]'),
('yuanqu-5756','紫花儿・瘦岩岩香消玉减，冷清清夜永更长，孤另另枕剩衾余。羞花闭月，','宋方壶','元','元曲','yuanqu','','[]','落雁沉鱼。',34,'元曲/yuanqu.json','["落雁沉鱼。", "踌躇，从今后谁寄萧娘一纸书？无情无绪，水淹蓝桥，梦断华胥。"]'),
('yuanqu-5757','调笑令・肺腑，恨怎舒？三叠阳关愁万缕。幽期密约欢爱处，动离愁暮云','宋方壶','元','元曲','yuanqu','','[]','无数。',18,'元曲/yuanqu.json','["无数。", "今夜月明何处宿？依依古岸黄芦。"]'),
('yuanqu-5758','秃厮儿・欢笑地不堪举目，回首处景物萧疏。星前月下谁共语？谩嗟吁，','宋方壶','元','元曲','yuanqu','','[]','何如？。',4,'元曲/yuanqu.json','["何如？。"]'),
('yuanqu-5759','尾・眼睁睁怎忍分飞去，痛杀我也吹箫伴侣！不付能恰住了送行客一帆风，','宋方壶','元','元曲','yuanqu','','[]','又添起助离愁半江雨。',62,'元曲/yuanqu.json','["又添起助离愁半江雨。", "踏青蝶使双双，蜂媒对对。", "燕语关关，莺声呖呖。", "仕女把芳寻，丫鬟将翠拾。", "节序宜，景物奇。", "丽日迟迟，和风习习。"]'),
('yuanqu-5760','紫花儿序・娇滴滴三春佳景，翠巍巍一带青山，锦重重满目芳菲。端的是','宋方壶','元','元曲','yuanqu','','[]','宜睛宜雨，堪咏堪题。',42,'元曲/yuanqu.json','["宜睛宜雨，堪咏堪题。", "畅好是幽微，嫩柳夭桃傍小溪。", "时遇着春光明媚，人贺丰年，民乐雍熙。"]'),
('yuanqu-5761','小桃红・雕阑花簇绣屏围，四季春为贵。万紫千红引人意，啭黄鹂，鸳鸯','宋方壶','元','元曲','yuanqu','','[]','如锦池塘睡。',25,'元曲/yuanqu.json','["如锦池塘睡。", "玩不尽山水无穷景致，更那堪花下杜鹃啼。"]'),
('yuanqu-5762','调笑令・赏奇葩异卉，休直待锦离披，多感谢春工造化机。彩绳悬画板秋','宋方壶','元','元曲','yuanqu','','[]','千戏，遍郊园幕天席地。',28,'元曲/yuanqu.json','["千戏，遍郊园幕天席地。", "动笙歌一派音韵美，列山灵水陆筵席。"]'),
('yuanqu-5763','圣药王・就着这花满溪，柳满堤，掩映着数株红杏出疏篱。风吹的酒力微，','宋方壶','元','元曲','yuanqu','','[]','景助的诗兴起，见滴溜溜墙外舞青旗，直吃的醉扶归。',24,'元曲/yuanqu.json','["景助的诗兴起，见滴溜溜墙外舞青旗，直吃的醉扶归。"]'),
('yuanqu-5764','尾声・庆风调雨顺升平日，保一统江山社稷。托赖着千千载仁主圣明朝，','宋方壶','元','元曲','yuanqu','','[]','齐仰贺万万岁吾皇大明国。',12,'元曲/yuanqu.json','["齐仰贺万万岁吾皇大明国。"]'),
('yuanqu-5765','双调・行香子寄情','李茂之','元','元曲','yuanqu','','[]','春满皇州，名遍青楼，二十年旖旎风流。',40,'元曲/yuanqu.json','["春满皇州，名遍青楼，二十年旖旎风流。", "金鞍玉勒，矮帽轻裘。", "谢娘诗，云子酿，雪儿讴。"]'),
('yuanqu-5766','乔木查・几愁花病酒，偏甚今番瘦。非是潘郎不奈秋，都因风韵它，引起','李茂之','元','元曲','yuanqu','','[]','闲愁。',3,'元曲/yuanqu.json','["闲愁。"]'),
('yuanqu-5767','拨不断・两绸缪，意相投，天然一点芳心透。年纪未三十过二九，多情莺','李茂之','元','元曲','yuanqu','','[]','燕蜂蝶友，速难成就。',10,'元曲/yuanqu.json','["燕蜂蝶友，速难成就。"]'),
('yuanqu-5768','天仙子・于飞愿，端的几时酬？会语应难，修书问候。铺玉版，写银钩，','李茂之','元','元曲','yuanqu','','[]','寄与娇羞。',18,'元曲/yuanqu.json','["寄与娇羞。", "真真的的美眷爱，不尚延由。"]'),
('yuanqu-5769','离亭带歇指煞・休违了剪发拈香咒，莫忘了并枕同衾褥。再休眉期眼约闲','李茂之','元','元曲','yuanqu','','[]','迤逗，娘间阻人调斗，枉教咱千生万受。',72,'元曲/yuanqu.json','["迤逗，娘间阻人调斗，枉教咱千生万受。", "常办着惜花心，空闲了画眉手。", "得又何如，失又何如，奈浮生迅景飞投。", "些儿富贵，多少风波。", "漫□谋，空驰聘，枉张罗。"]'),
('yuanqu-5770','乔木查・选溪山好处结茅屋，栽花果，人我境番成安乐窝。算来忧虑少，','李茂之','元','元曲','yuanqu','','[]','自投灾祸。',5,'元曲/yuanqu.json','["自投灾祸。"]'),
('yuanqu-5771','拨不断・得蹉跎，把器虚，公案教参破。眉上顿开愁锁，心头泼杀无名火，','李茂之','元','元曲','yuanqu','','[]','俺且学卖呆妆捋。',8,'元曲/yuanqu.json','["俺且学卖呆妆捋。"]'),
('yuanqu-5772','筝笆序・人间事，一自饱经过，日月双轮，乾坤六合。麟阁将，玉堂臣，','李茂之','元','元曲','yuanqu','','[]','总被消磨。',21,'元曲/yuanqu.json','["总被消磨。", "人生幻化待则甚磨，便似一梦南柯。"]'),
('yuanqu-5773','离亭宴带歇指煞・闲来膝上横琴坐，醉时节林下和衣卧。唱得快活，乐天','李茂之','元','元曲','yuanqu','','[]','知命随缘过。',81,'元曲/yuanqu.json','["知命随缘过。", "为伴侣唯三个，明月清风共我。", "再不把利名侵，且须将是非躲。", "扌颠竹分茶，摘叶拈花，圈儿中稍自矜夸。", "画眉打眼，料嘴敲牙。", "要罚馒只除是瓮生根，盆生蔓，甑生芽。"]'),
('yuanqu-5774','乔木查・俺虽不是个还魂子弟，晓四六通合剌，锦套头花圈圆且吉咱。正','李茂之','元','元曲','yuanqu','','[]','迟看两念家，打鼓弄琵琶。',12,'元曲/yuanqu.json','["迟看两念家，打鼓弄琵琶。"]'),
('yuanqu-5775','拨不断・你待把我做燕儿般拿，我待把你做兔儿般叉，不信三文钱买取个','李茂之','元','元曲','yuanqu','','[]','龟儿卦。',41,'元曲/yuanqu.json','["龟儿卦。", "团衫是纸，系腰是麻，包髻是瓦。", "我罩篱是皮，卧是铁枪头是蜡，咱两个一般乔话。"]'),
('yuanqu-5776','天仙令・添潇洒，朝夕是甚生涯？女仗唇枪，娘凭嘴抹，寻缝儿觅撒花。','李茂之','元','元曲','yuanqu','','[]','早索与他异锦轻纱，动不动五奴闲坐衙，知他是理会甚么官法？。',29,'元曲/yuanqu.json','["早索与他异锦轻纱，动不动五奴闲坐衙，知他是理会甚么官法？。"]'),
('yuanqu-5777','离亭宴带歇拍煞・把条款别体倒违礼煞，寨儿中、监狱儿内、禁牢儿里下，','李茂之','元','元曲','yuanqu','','[]','则恁傍人每鉴咱。',91,'元曲/yuanqu.json','["则恁傍人每鉴咱。", "吃不过姐姐焦、娘娘哝、婆婆骂，欲待要离恁那壳中应难罢，只除是天摧地塌。", "最难禁碎揪ㄎ、胡腐掐、零碎抹，又没耕种千家生马，寻取个回头儿调发。", "不使钱恁娘嗔，使了钱俺那耶打。"]'),
('yuanqu-5778','越调・小桃红消遣','爱山','元','元曲','yuanqu','','[]','一溪流水水溪云，雨霁山光润，野鸟山花破愁闷。',107,'元曲/yuanqu.json','["一溪流水水溪云，雨霁山光润，野鸟山花破愁闷。", "乐闲身，拖条藜杖家家问。", "问谁家有酒，见青帘高挂，高挂在杨柳岸杏花村。", "世间惟有酒忘忧，酒况谁参透？酒解愁肠破亻孱亻愁。", "到心头，三杯涤尽胸中垢和颜润色，延年益寿，一醉解千愁。"]'),
('yuanqu-5779','仙吕・寄生草饮','白朴','元','元曲','yuanqu','','[]','长醉后方何碍，不醒时有甚思。',56,'元曲/yuanqu.json','["长醉后方何碍，不醒时有甚思。", "糟腌两个功名字，醅淹千古兴亡事，曲埋万丈虹霓志。", "不达时皆笑屈原非，但知音尽说陶潜是。"]'),
('yuanqu-5780','仙吕・醉中天佳人脸上黑痣','白朴','元','元曲','yuanqu','','[]','疑是杨妃在，怎脱马嵬灾。',46,'元曲/yuanqu.json','["疑是杨妃在，怎脱马嵬灾。", "曾与明皇捧砚来，美脸风流杀。", "叵奈挥毫李白，觑着娇态，洒松烟点破桃腮。"]'),
('yuanqu-5781','双调・得胜乐春','白朴','元','元曲','yuanqu','','[]','丽日迟，和风习，共王孙公子游戏。',273,'元曲/yuanqu.json','["丽日迟，和风习，共王孙公子游戏。", "醉酒淹衫袖湿，簪花压帽檐低。", "夏酷暑天，葵榴发。", "喷鼻香十里荷花，兰舟斜缆垂杨下。", "只宜铺枕簟、向凉亭披襟散发。", "秋玉露冷，蛩吟砌。", "听落叶西风渭水，寒雁儿长空嘹唳。", "陶元亮醉在东篱。", "冬密布云，初交腊。", "偏宜去扫雪烹茶，羊羔酒添价。", "胆瓶内温水浸梅花。", "又独自寝，难成梦，睡觉来怀儿里抱空。", "六幅罗裙宽褪，玉腕上钏儿松。", "独自走，踏成道，空走了千遭万遭。", "肯不肯疾些儿通报，休直到教担阁得天明了。", "红日晚，遥天暮，老树寒鸦几簇。", "咱为甚妆妆频觑，怕有那新雁儿寄来书。", "红日晚，残霞在，秋水共长天一色。", "寒雁儿呀呀的天外，怎生不捎带个字儿来？套数。"]'),
('yuanqu-5782','仙吕・点绛唇','白朴','元','元曲','yuanqu','','[]','金凤钗分，玉京人去，秋萧洒。',25,'元曲/yuanqu.json','["金凤钗分，玉京人去，秋萧洒。", "晚来闲暇，针线收拾罢。"]'),
('yuanqu-5784','混江龙・断人肠处，天边残照水边霞。枯荷宿鹭，远树栖鸦。败叶纷纷拥','白朴','元','元曲','yuanqu','','[]','砌石，修竹珊珊扫窗纱。',25,'元曲/yuanqu.json','["砌石，修竹珊珊扫窗纱。", "黄昏近，愁生砧杵，怨入琵琶。"]'),
('yuanqu-5785','穿窗月・忆疏狂阻隔天涯，怎知人埋冤他。吟鞭袅青骢马，莫吃秦楼酒，','白朴','元','元曲','yuanqu','','[]','谢家茶，不思量执手临岐话。',13,'元曲/yuanqu.json','["谢家茶，不思量执手临岐话。"]'),
('yuanqu-5786','元和令・自从绝雁书，几度结龟卦。翠眉长是锁离愁，玉容憔悴煞。自元','白朴','元','元曲','yuanqu','','[]','宵等待过重阳，甚犹然不到家。',14,'元曲/yuanqu.json','["宵等待过重阳，甚犹然不到家。"]'),
('yuanqu-5787','上马娇煞・欢会少，烦恼多，心绪乱如麻。偶然行至东篱下，自嗟自呀，','白朴','元','元曲','yuanqu','','[]','冷清清和月对黄花。',9,'元曲/yuanqu.json','["冷清清和月对黄花。"]'),
('yuanqu-5788','归塞北・貂裘客，嘉庆卷帘看。好景画图收不尽，好题诗句咏尤难，疑在','白朴','元','元曲','yuanqu','','[]','玉壶间。',4,'元曲/yuanqu.json','["玉壶间。"]'),
('yuanqu-5789','好观音・富贵人家应须惯，红炉暖不畏严寒。开宴邀宾列翠鬟，拚酡颜，','白朴','元','元曲','yuanqu','','[]','畅饮休辞惮。',6,'元曲/yuanqu.json','["畅饮休辞惮。"]'),
('yuanqu-5790','幺篇・劝酒佳人擎金盏，当歌者款撒香檀。歌罢喧喧笑语繁，夜将阑，画','白朴','元','元曲','yuanqu','','[]','烛银光灿。',5,'元曲/yuanqu.json','["烛银光灿。"]'),
('yuanqu-5791','结音・似觉筵间香风散，香风散非麝非兰。醉眼朦腾问小蛮，多管是南轩','白朴','元','元曲','yuanqu','','[]','蜡梅绽。',4,'元曲/yuanqu.json','["蜡梅绽。"]'),
('yuanqu-5792','小石调・恼煞人','白朴','元','元曲','yuanqu','','[]','又是红轮西坠，残霞照万顷银波。',37,'元曲/yuanqu.json','["又是红轮西坠，残霞照万顷银波。", "江上晚景寒烟，雾蒙蒙、风细细，阻隔离人箫索。"]'),
('yuanqu-5793','幺篇・宋玉悲秋愁闷，江淹梦笔寂寞。人间岂无成与破，想别离情绪，世','白朴','元','元曲','yuanqu','','[]','界里只有俺一个。',8,'元曲/yuanqu.json','["界里只有俺一个。"]'),
('yuanqu-5794','幺篇・故人杳杳，长江风送，听胡笳沥沥声韵聒。一轮皓月朗，几处鸣榔，','白朴','元','元曲','yuanqu','','[]','时复唱和渔歌。',52,'元曲/yuanqu.json','["时复唱和渔歌。", "转无那，沙汀蓼岸，一点渔灯相照，寂寞古渡停画舸。", "双生无语泪珠落，呼仆隶指泼水手，在意扶柁。"]'),
('yuanqu-5796','双调・乔木查对景','白朴','元','元曲','yuanqu','','[]','海棠初雨歇，杨柳轻烟惹，碧草茸茸辅四野。',31,'元曲/yuanqu.json','["海棠初雨歇，杨柳轻烟惹，碧草茸茸辅四野。", "俄然回首处，乱红堆雪。"]'),
('yuanqu-5798','挂搭沽序・倏忽早庭梧坠，荷盖缺。院宇砧韵切，蝉声咽。露白霜结，水','白朴','元','元曲','yuanqu','','[]','冷风高，长天雁字斜，秋香次第天彻。',17,'元曲/yuanqu.json','["冷风高，长天雁字斜，秋香次第天彻。"]'),
('yuanqu-5799','幺篇・不觉的冰澌结，彤云布，朔风凛冽。乱扑吟窗，谢女堪题，柳絮飞','白朴','元','元曲','yuanqu','','[]','玉砌。',53,'元曲/yuanqu.json','["玉砌。", "长郊万里，粉污遥山千叠。", "去路赊，渔叟散，披蓑去，江上清绝。", "幽悄闲庭院，舞榭歌楼酒力怯，人在水晶宫阙。"]'),
('yuanqu-5800','幺篇・岁华如流水，消磨尽，自古豪杰，盖世功名总是空，方信花开易谢，','白朴','元','元曲','yuanqu','','[]','始知人生多别。',56,'元曲/yuanqu.json','["始知人生多别。", "忆故园，漫叹嗟，旧游池铺，番做了孤踪兔穴。", "休痴休呆，蜗角蝇头，名亲共利切。", "富贵似花上蝶，春宵梦说。"]'),
('yuanqu-5802','双调・殿前欢大都西山','唐毅夫','元','元曲','yuanqu','','[]','冷云间，夕阳楼外数峰闲，等闲不许俗人看。',58,'元曲/yuanqu.json','["冷云间，夕阳楼外数峰闲，等闲不许俗人看。", "雨髻烟鬟，倚西风十二阑。", "休长叹，不多时暮霭风吹散。", "西山看我，我看西山。", "套数。"]'),
('yuanqu-5803','南吕・一枝花怨雪','唐毅夫','元','元曲','yuanqu','','[]','不呈六出祥，岂应三白瑞。',59,'元曲/yuanqu.json','["不呈六出祥，岂应三白瑞。", "易添身上冷，能使腹中肌。", "有甚稀奇，无主向沿街坠，不着人到处飞。", "暗敲窗有影无形，偷入户潜踪蹑迹。"]'),
('yuanqu-5804','梁州・才苫上茅庵草舍，又钻入破壁疏篱。似杨花滚滚轻狂势。你几曾见','唐毅夫','元','元曲','yuanqu','','[]','贵公子锦ブ绣褥？你多曾伴老渔翁箬笠蓑衣？为飘风胡做胡为，怕腾云相趁相随。',120,'元曲/yuanqu.json','["贵公子锦ブ绣褥？你多曾伴老渔翁箬笠蓑衣？为飘风胡做胡为，怕腾云相趁相随。", "只着你冻的个孟浩然挣挣痴痴，只着你逼的个林和靖钦钦历历。", "只着你阻的个韩退之哭哭啼啼。", "更长，漏迟。", "被窝中无半点儿阳和气，恼人眠，搅人睡。", "你那冷燥皮肤似铁石，着我怎敢相偎。"]'),
('yuanqu-5805','尾・一冬酒债因他累，千里关山被你迷。似这等浪蕊闲花，也不是久长计。','唐毅夫','元','元曲','yuanqu','','[]','尽飘零数日，扫除做一堆，我将你温不热薄情化做了水。',25,'元曲/yuanqu.json','["尽飘零数日，扫除做一堆，我将你温不热薄情化做了水。"]'),
('yuanqu-5806','包待制三勘蝴蝶梦・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','仔细寻思，两回三次，这场蹊跷事。',33,'元曲/yuanqu.json','["仔细寻思，两回三次，这场蹊跷事。", "走的我气咽声丝，恨不的两肋生双翅。"]'),
('yuanqu-5807','包待制三勘蝴蝶梦・油葫芦','关汉卿','元','元曲','yuanqu','','[]','你觑那着伤处一埚青间紫，可早停着死尸。',78,'元曲/yuanqu.json','["你觑那着伤处一埚青间紫，可早停着死尸。", "你可便从来忧念没家私，昨朝怎晓今朝死，今日不知来日事。", "血模糊污了一身，软答剌冷了四肢，黄甘甘面色如金纸，干叫了一炊时。"]'),
('yuanqu-5808','包待制三勘蝴蝶梦・天下乐','关汉卿','元','元曲','yuanqu','','[]','救不活将咱没乱死！咱家私、自暗思，到明朝若是出殡时，又没他一陌纸，空排着三个儿，这正是家贫也显孝子。',50,'元曲/yuanqu.json','["救不活将咱没乱死！咱家私、自暗思，到明朝若是出殡时，又没他一陌纸，空排着三个儿，这正是家贫也显孝子。"]'),
('yuanqu-5809','包待制三勘蝴蝶梦・那吒令','关汉卿','元','元曲','yuanqu','','[]','他本是太学中殿试，"怎想他拳头上便死？今日个则落得长街上检尸。',50,'元曲/yuanqu.json','["他本是太学中殿试，\"怎想他拳头上便死？今日个则落得长街上检尸。", "更做道见职官，俺是个穷儒士，也索称词。"]'),
('yuanqu-5810','包待制三勘蝴蝶梦・鹊踏枝','关汉卿','元','元曲','yuanqu','','[]','若是俺到官时，和您去对情词，使不着国戚皇亲、玉叶金枝；便是他龙孙帝子，打杀人要吃官司！。',44,'元曲/yuanqu.json','["若是俺到官时，和您去对情词，使不着国戚皇亲、玉叶金枝；便是他龙孙帝子，打杀人要吃官司！。"]'),
('yuanqu-5811','包待制三勘蝴蝶梦・寄生草','关汉卿','元','元曲','yuanqu','','[]','你可便斟量着做，似这般甚意儿？你三人平昔无瑕疵，你三人打死虽然是，你三人倒惹下刑名事。',65,'元曲/yuanqu.json','["你可便斟量着做，似这般甚意儿？你三人平昔无瑕疵，你三人打死虽然是，你三人倒惹下刑名事。", "则被这清风明月两闲人，送了你玉堂金马三学士。"]'),
('yuanqu-5812','包待制三勘蝴蝶梦・金盏儿','关汉卿','元','元曲','yuanqu','','[]','想当时，你可也不三思？似这般逞凶撒泼干行止，无过恃着你有权势、有金资。',71,'元曲/yuanqu.json','["想当时，你可也不三思？似这般逞凶撒泼干行止，无过恃着你有权势、有金资。", "则道是长街上妆好汉，谁想你血泊内也停尸！正是\"将军着痛箭，还似射人时\"。"]'),
('yuanqu-5813','包待制三勘蝴蝶梦・醉中天','关汉卿','元','元曲','yuanqu','','[]','咱每日一瓢饮、一箪食，有几双箸、几张匙；若到官司使钞时，则除典当了闲文字。',78,'元曲/yuanqu.json','["咱每日一瓢饮、一箪食，有几双箸、几张匙；若到官司使钞时，则除典当了闲文字。", "（带云）便这等，也不济事。", "（唱）你合死呵今朝便死。", "虽道是杀人公事，也落个孝顺名儿。"]'),
('yuanqu-5814','包待制三勘蝴蝶梦・金盏儿','关汉卿','元','元曲','yuanqu','','[]','苦孜孜，泪丝丝，这场灾祸从天至，把俺横拖倒拽怎推辞！一壁厢碜可可停着老子，一壁厢眼睁睁送了孩儿。',65,'元曲/yuanqu.json','["苦孜孜，泪丝丝，这场灾祸从天至，把俺横拖倒拽怎推辞！一壁厢碜可可停着老子，一壁厢眼睁睁送了孩儿。", "可知道\"福无重受日，祸有并来时\"。"]'),
('yuanqu-5815','包待制三勘蝴蝶梦・后庭花','关汉卿','元','元曲','yuanqu','','[]','再休想跳龙门、折桂枝，少不得为亲爷遭横死。',91,'元曲/yuanqu.json','["再休想跳龙门、折桂枝，少不得为亲爷遭横死。", "从来个人命当还报，料应他天公不受私。", "（带云）儿也，（唱）不由我不嗟咨，几回家看视，现如今拿住尔，到公庭责口词，下脑箍使拶子，这其间痛怎支？。"]'),
('yuanqu-5816','包待制三勘蝴蝶梦・柳叶儿','关汉卿','元','元曲','yuanqu','','[]','怕不待的一确二，早招承死罪无辞。',51,'元曲/yuanqu.json','["怕不待的一确二，早招承死罪无辞。", "（带云）儿也，（唱）你为亲爷雪恨当如是，便相次赴阴司，也得个孝顺名儿。"]'),
('yuanqu-5817','包待制三勘蝴蝶梦・赚煞','关汉卿','元','元曲','yuanqu','','[]','为甚我教你看诗书、习经史？俺待学孟母三移教子。',107,'元曲/yuanqu.json','["为甚我教你看诗书、习经史？俺待学孟母三移教子。", "不能勾金榜上分明题姓氏，则落得犯由牌书写名儿。", "想当时，也是不得已为之。", "便做道审得情真，奏过圣旨，只不过是一人处死；须断不了王家宗祀，那里便灭门绝户了俺一家儿？（同下）。"]'),
('yuanqu-5818','包待制三勘蝴蝶梦・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','解到这无人情御史台，元来是有官法开封府。',85,'元曲/yuanqu.json','["解到这无人情御史台，元来是有官法开封府。", "把三个未发迹小秀士，生扭做吃勘问死囚徒。", "空教我意下踌躇，把不定心惊惧，赤紧的贼儿胆底虚。", "教我把罪犯私下招承，不比那小去处官司孔目。"]'),
('yuanqu-5819','包待制三勘蝴蝶梦・梁州第七','关汉卿','元','元曲','yuanqu','','[]','这开封府王条清正，不比那中牟县官吏糊涂。',167,'元曲/yuanqu.json','["这开封府王条清正，不比那中牟县官吏糊涂。", "扑咚咚阶下升衙鼓，唬的我手忙脚乱，使不得胆大心粗；惊的我魂飞魄丧，走的我力尽筋舒。", "这公事不比寻俗，就中间担负公徒。", "嗨、嗨、嗨，一壁厢老夫主在地停尸；更、更、更，赤紧地子母每坐牢系狱；呀、呀、呀，眼见的弟兄每受刃遭诛。", "早是怕怖，我向这屏墙边侧耳偷睛觑：谁曾见这官府？则今日当厅定祸福，谁实谁虚？。"]'),
('yuanqu-5820','包待制三勘蝴蝶梦・贺新郎','关汉卿','元','元曲','yuanqu','','[]','孩儿每万千死罪犯公徒。',136,'元曲/yuanqu.json','["孩儿每万千死罪犯公徒。", "那厮每情理难容，俺孩儿杀人可恕。", "俺穷滴滴寒贱为黎庶，告爷爷与孩儿每做主。", "这三个自小来便学文书，他则会依经典、习礼义，那里会定计策、厮亏图？百般的拷打难分诉。", "岂不闻\"三人误大事，六耳不通谋\"？（包待制云）不打不招。", "张千，与我加力打者！（正旦悲科，唱）。"]'),
('yuanqu-5821','包待制三勘蝴蝶梦・隔尾','关汉卿','元','元曲','yuanqu','','[]','俺孩儿犯着徒流绞斩萧何律，枉读了恭俭温良孔圣书。',65,'元曲/yuanqu.json','["俺孩儿犯着徒流绞斩萧何律，枉读了恭俭温良孔圣书。", "拷打的浑身上怎生觑！打的来伤筋动骨，更疼似悬头刺股。", "他每爷饭娘羹，何曾受这般苦！。"]'),
('yuanqu-5822','包待制三勘蝴蝶梦・牧羊关','关汉卿','元','元曲','yuanqu','','[]','这个是金呵，有甚么难熔铸？（包待制云）敢是石和打死人来？（正旦唱）这个石呵，怎做的虚？（包待制云）敢是铁和打死人来？（正旦唱）这个便是铁呵，怎当那官法如炉？（包',190,'元曲/yuanqu.json','["这个是金呵，有甚么难熔铸？（包待制云）敢是石和打死人来？（正旦唱）这个石呵，怎做的虚？（包待制云）敢是铁和打死人来？（正旦唱）这个便是铁呵，怎当那官法如炉？（包待制云）打这赖肉顽皮。", "（正旦唱）非干是孩儿每赖肉顽皮，委的衔冤负屈。", "（包待制云）张千，便好道\"杀人的偿命，欠债的还钱\"。", "把那大的小厮，拿出去与他偿命。", "（正旦唱）眼睁睁难搭救，簇拥着下阶除。", "教我两下里难顾瞻，百般的没是处。"]'),
('yuanqu-5823','包待制三勘蝴蝶梦・隔尾','关汉卿','元','元曲','yuanqu','','[]','一壁厢大哥行牵挂着娘肠肚，一壁厢二哥行关连着痛肺腑。',64,'元曲/yuanqu.json','["一壁厢大哥行牵挂着娘肠肚，一壁厢二哥行关连着痛肺腑。", "要偿命，留下孩儿，宁可将婆子去。", "似这般狠毒，又无处告诉，手扳定枷梢叫声儿屈。"]'),
('yuanqu-5824','包待制三勘蝴蝶梦・牧羊关','关汉卿','元','元曲','yuanqu','','[]','这孩儿虽不曾亲生养，却须是咱乳哺。',187,'元曲/yuanqu.json','["这孩儿虽不曾亲生养，却须是咱乳哺。", "（包待制云）这第二的呢？（正旦唱）这一个偌大小，是老婆子抬举。", "（包待制云）兀那小的呢？（正旦打悲科，唱）这一个是我的亲儿，这两个我是他的继母。", "（包待制云）兀那婆子，近前来。", "你差了也，前家儿着一个偿命，留着你亲生孩儿养活你可不好那！（正旦云）爷爷差了也！（唱）不争着前家儿偿了命，显得后尧婆忒心毒。", "我若学嫉妒的桑新妇，不羞见那贤达的鲁义姑！。"]'),
('yuanqu-5825','包待制三勘蝴蝶梦・红芍药','关汉卿','元','元曲','yuanqu','','[]','浑身是口怎支吾？恰似个没嘴的葫芦。',66,'元曲/yuanqu.json','["浑身是口怎支吾？恰似个没嘴的葫芦。", "打的来皮开肉绽损肌肤，鲜血模糊，恰浑似活地狱。", "三个儿都教死去。", "你都官官相为倚亲属，更做道国戚皇族。"]'),
('yuanqu-5826','包待制三勘蝴蝶梦・菩萨梁州','关汉卿','元','元曲','yuanqu','','[]','大哥罪犯遭诛，二哥死生别路，三哥身归地府，干闪下我这老孽身躯！大哥孝顺识亲疏，二哥留下着当门户，第三个哥哥休言语，你偿命正合去。',85,'元曲/yuanqu.json','["大哥罪犯遭诛，二哥死生别路，三哥身归地府，干闪下我这老孽身躯！大哥孝顺识亲疏，二哥留下着当门户，第三个哥哥休言语，你偿命正合去。", "常言道\"三人同行小的苦\"，再不须大叫高呼。"]'),
('yuanqu-5827','包待制三勘蝴蝶梦・黄钟尾','关汉卿','元','元曲','yuanqu','','[]','包龙图往常断事曾着数，今日为官忒慕古。',135,'元曲/yuanqu.json','["包龙图往常断事曾着数，今日为官忒慕古。", "枉教你坐黄堂、带虎符，受荣华、请俸禄。", "俺孩儿好冤屈，不睹事下牢狱。", "割舍了待泼做：告都堂、诉省部；撅皇城、打怨鼓；见銮舆、便唐突。", "呆老婆唱今古，又无人肯做主，则不如觅死处，眼不见鳏寡孤独；也强如没归着，痛煞煞、哭啼啼、活受苦！（下）。"]'),
('yuanqu-5828','包待制三勘蝴蝶梦・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','遥望着死囚牢，恰离了悲田院，谁敢道半步俄延！排门儿叫化都寻遍，讨了些泼剩饭和杂面。',41,'元曲/yuanqu.json','["遥望着死囚牢，恰离了悲田院，谁敢道半步俄延！排门儿叫化都寻遍，讨了些泼剩饭和杂面。"]'),
('yuanqu-5829','包待制三勘蝴蝶梦・滚绣球','关汉卿','元','元曲','yuanqu','','[]','俺孩儿本思量做状元，坐琴堂、请俸钱。',100,'元曲/yuanqu.json','["俺孩儿本思量做状元，坐琴堂、请俸钱。", "谁曾遭这般刑宪，又不曾犯\"五刑之属三千\"。", "我不肯吃、不肯穿，烧地卧、炙地眠，谁曾受这般贫贱！正按着陈婆婆古语常言，他须\"不求金玉重重贵，却甚儿孙个个贤\"，受煞熬煎。"]'),
('yuanqu-5830','包待制三勘蝴蝶梦・倘秀才','关汉卿','元','元曲','yuanqu','','[]','叫化的剩饭重煎再煎，补衲的破袄儿翻穿了正穿。',93,'元曲/yuanqu.json','["叫化的剩饭重煎再煎，补衲的破袄儿翻穿了正穿。", "（云）哥哥，则这件旧衣服送你罢！（唱）有这个旧褐袖，与哥哥且做些冤苦钱。", "（张千云）我也不要你的。", "（正旦唱）谢哥哥相觑当，厮周全，把孩儿每可怜。"]'),
('yuanqu-5831','包待制三勘蝴蝶梦・脱布衫','关汉卿','元','元曲','yuanqu','','[]','争奈一家一计，肠肚萦牵；一上一下，语话熬煎；一左一右，把孩儿顾恋；一捋一把，雨泪涟涟。',43,'元曲/yuanqu.json','["争奈一家一计，肠肚萦牵；一上一下，语话熬煎；一左一右，把孩儿顾恋；一捋一把，雨泪涟涟。"]'),
('yuanqu-5832','包待制三勘蝴蝶梦・醉太平','关汉卿','元','元曲','yuanqu','','[]','数说起罪愆，委实的衔冤，我这里烦烦恼恼怨青大，告哥哥可怜。',76,'元曲/yuanqu.json','["数说起罪愆，委实的衔冤，我这里烦烦恼恼怨青大，告哥哥可怜。", "他三个足丢没乱眼脑剔抽秃刷转，依柔乞煞手脚滴羞笃速战；迷留没乱救他叫破俺喉咽，气的来前合后偃。"]'),
('yuanqu-5833','包待制三勘蝴蝶梦・笑和尚','关汉卿','元','元曲','yuanqu','','[]','我、我、我两三步走向前，将、将、将把饭食从头劝，我、我、我一匙匙都抄遍；你、你、你胡噎饥，你、你、你润喉咽。',139,'元曲/yuanqu.json','["我、我、我两三步走向前，将、将、将把饭食从头劝，我、我、我一匙匙都抄遍；你、你、你胡噎饥，你、你、你润喉咽。", "（王三云）娘也，我也吃些儿。", "（正旦唱）石和尚好共歹一口口刚刚咽。", "（旦做倾饭料，云）大哥，这里有个烧饼，你吃，休教石和看见。", "二哥，这里有个烧饼，你吃，休教石和看见。", "（唱）。"]'),
('yuanqu-5834','包待制三勘蝴蝶梦・叨叨令','关汉卿','元','元曲','yuanqu','','[]','叫化的些残汤剩饭，那里有重罗面！你不想堂食玉酒琼林宴，想当初长枷钉出中牟县，却不道布衣走上黄金殿。',80,'元曲/yuanqu.json','["叫化的些残汤剩饭，那里有重罗面！你不想堂食玉酒琼林宴，想当初长枷钉出中牟县，却不道布衣走上黄金殿。", "兀的不苦杀人也么哥！兀的不苦杀人也么哥！告你个提牢押狱行方便。"]'),
('yuanqu-5835','包待制三勘蝴蝶梦・上小楼','关汉卿','元','元曲','yuanqu','','[]','将两个哥哥放免，把第三的孩儿推转；想着我咽苦吞甘，十月怀耽，乳哺三年。',61,'元曲/yuanqu.json','["将两个哥哥放免，把第三的孩儿推转；想着我咽苦吞甘，十月怀耽，乳哺三年。", "不争教大哥哥、二哥哥身遭刑宪，教人道桑新妇不分良善。"]'),
('yuanqu-5836','包待制三勘蝴蝶梦・幺篇','关汉卿','元','元曲','yuanqu','','[]','你本待冤报冤，倒做了颠倒颠。',105,'元曲/yuanqu.json','["你本待冤报冤，倒做了颠倒颠。", "岂不闻杀人偿命，罪而当刑，死而无怨。", "（做看王三科，唱）若是我两三番将他留恋，教人道后尧婆两头三面。", "（王大、王二云）母亲，我怎舍得兄弟也！（正旦云）大哥、二哥家去来，休烦恼者！（唱）。"]'),
('yuanqu-5837','包待制三勘蝴蝶梦・快活三','关汉卿','元','元曲','yuanqu','','[]','眼见的你两个得生天，单则你小兄弟丧黄泉。',84,'元曲/yuanqu.json','["眼见的你两个得生天，单则你小兄弟丧黄泉。", "（做觑王三悲科，唱）教我扭回身，忍不住泪涟涟。", "（王大、王二悲科）（正旦云）罢、罢、罢，但留的你两个呵，（唱）他便死也我甘心情愿。"]'),
('yuanqu-5838','包待制三勘蝴蝶梦・尾煞','关汉卿','元','元曲','yuanqu','','[]','做爷的不曾烧一陌纸钱，做儿的又当了罪愆，爷和儿要见何时见？若要再相逢一面，则除是梦儿中咱子母团圆。',230,'元曲/yuanqu.json','["做爷的不曾烧一陌纸钱，做儿的又当了罪愆，爷和儿要见何时见？若要再相逢一面，则除是梦儿中咱子母团圆。", "（王大、王二随下）（王三云）张千哥哥，我大哥、二哥都那里去了？（张千云）老爷的言语，你大哥、二哥都饶了，着养活你母亲去；只着你替葛彪偿命。", "（王三云）饶了我两个哥哥，着我偿命去，把这两面枷我都带上。", "只是我明日怎么样死？（张千云）把你盆吊死，三十板高墙丢过去。", "（王三云）哥哥，你丢我时放仔细些，我肚子上有个疖子哩！（张千云）你性命也不保，还管你甚么疖子！（王三唱）。"]'),
('yuanqu-5839','包待制三勘蝴蝶梦・端正好','关汉卿','元','元曲','yuanqu','','[]','腹揽五车书，（张千云）你怎么唱起来？（王三云）是曲尾。',72,'元曲/yuanqu.json','["腹揽五车书，（张千云）你怎么唱起来？（王三云）是曲尾。", "（唱）都是些《礼记》和《周易》。", "眼睁睁死限相随，指望待为官为相身荣贵，今日个毕罢了名和利。"]'),
('yuanqu-5840','包待制三勘蝴蝶梦・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','我从未拔白悄悄出城来，恐怕外人知大惊小怪。',60,'元曲/yuanqu.json','["我从未拔白悄悄出城来，恐怕外人知大惊小怪。", "我叫化的乱烘烘一陌纸，拾得粗坌坌几根柴。", "俺孩儿落不得席卷椽抬，谁想有这一解！。"]'),
('yuanqu-5841','包待制三勘蝴蝶梦・夜行船','关汉卿','元','元曲','yuanqu','','[]','慌急列教咱观了面色，血模糊污尽尸骸。',42,'元曲/yuanqu.json','["慌急列教咱观了面色，血模糊污尽尸骸。", "我与你慌解下麻绳，急松开衣带，您疾忙向前来扶策。"]'),
('yuanqu-5842','包待制三勘蝴蝶梦・挂玉钩','关汉卿','元','元曲','yuanqu','','[]','你与我揪住头心掐下颏，我与你高阜处招魂魄。',71,'元曲/yuanqu.json','["你与我揪住头心掐下颏，我与你高阜处招魂魄。", "石和哎，贪慌处将孩儿落了鞋，你便叫煞他、怎得他瞅睬？空教我闷转加、愁无奈，只落得哭哭啼啼、怨怨哀哀。"]'),
('yuanqu-5843','包待制三勘蝴蝶梦・沽美酒','关汉卿','元','元曲','yuanqu','','[]','我将这老精神强打拍，小名儿叫的明白，你个孝顺的石和安在哉？则被他抛杀您奶奶，教我空没乱把地皮掴。',48,'元曲/yuanqu.json','["我将这老精神强打拍，小名儿叫的明白，你个孝顺的石和安在哉？则被他抛杀您奶奶，教我空没乱把地皮掴。"]'),
('yuanqu-5844','包待制三勘蝴蝶梦・太平令','关汉卿','元','元曲','yuanqu','','[]','空教我哭啼啼自敦自摔，百般的唤不回来。',89,'元曲/yuanqu.json','["空教我哭啼啼自敦自摔，百般的唤不回来。", "也是我多灾多害，急煎煎不宁不耐。", "（云）石和孩儿呵！（王三上，应云）我在这里！（正旦唱）教我左猜、右猜，不知是那里应来？呀，莫不是山精水怪！。"]'),
('yuanqu-5845','包待制三勘蝴蝶梦・川拨棹','关汉卿','元','元曲','yuanqu','','[]','这场灾，一时间命运衰；早则解放愁怀，喜笑盈腮。',82,'元曲/yuanqu.json','["这场灾，一时间命运衰；早则解放愁怀，喜笑盈腮。", "我则道石沉大海！（云）大哥、二哥，您两个管着甚么哩？（唱）这言语休见责。", "（云）您两个好不仔细。", "抬这尸首来做甚？（唱）。"]'),
('yuanqu-5846','包待制三勘蝴蝶梦・殿前欢','关汉卿','元','元曲','yuanqu','','[]','孩儿，你也合把眼睁开，却把谁家尸首与我背将来？也不是提鱼穿柳欢心大，也不是鬼使神差。',115,'元曲/yuanqu.json','["孩儿，你也合把眼睁开，却把谁家尸首与我背将来？也不是提鱼穿柳欢心大，也不是鬼使神差。", "虽然道死是他命该，你为甚无妨碍？（王三云）孩儿知道没事，是包爷爷吩咐教我背出来的。", "（正旦唱）常言道\"老实的终须在\"！把错抬的尸首，你与我土内藏埋。"]'),
('yuanqu-5847','包待制三勘蝴蝶梦・水仙子','关汉卿','元','元曲','yuanqu','','[]','九重天飞下纸赦书来，您三下里休将招状责，一齐的望阙疾参拜。',68,'元曲/yuanqu.json','["九重天飞下纸赦书来，您三下里休将招状责，一齐的望阙疾参拜。", "愿的圣明君千万载，更胜如枯树花开。", "捱了些脓血债，受彻了牢狱灾，今日个苦尽甘来。"]'),
('yuanqu-5848','包待制三勘蝴蝶梦・鸳鸯煞','关汉卿','元','元曲','yuanqu','','[]','不甫能黑漫漫填满这沉冤海，昏腾腾打出了迷魂寨；愿待制位列三公，日转千阶。',89,'元曲/yuanqu.json','["不甫能黑漫漫填满这沉冤海，昏腾腾打出了迷魂寨；愿待制位列三公，日转千阶。", "畅道娘加做贤德夫人，儿加做中牟县宰，赦得俺一家儿今后都安泰。", "且休提这恩德无涯，单则是子母团圆，大古里彩！。"]'),
('yuanqu-5849','随何赚风魔蒯通・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','只为那焚典坑儒，烦刑重赋，因此上人心怒。',36,'元曲/yuanqu.json','["只为那焚典坑儒，烦刑重赋，因此上人心怒。", "共逐秦鹿，今日早扶立的这英明主。"]'),
('yuanqu-5850','随何赚风魔蒯通・混江龙','无名氏','元','元曲','yuanqu','','[]','想我张良未遇，也则是个预知秦世避人夫。',171,'元曲/yuanqu.json','["想我张良未遇，也则是个预知秦世避人夫。", "不甫能平定了刘家天下，才得做大汉司徒。", "我想今日封侯得这陈留邑，索强如少年逃难下邳初。", "我也曾劈划着黄公略法，酝酿着吕望韬书。", "佐高皇南征北讨，随诸将东荡西除。", "傍秋风将楚歌唱彻，早吹散了垓下军卒。", "那重瞳有千般英勇，怎出的这十面埋伏？逼得他无颜敢再向东吴，在乌江边自刎也是天之数。", "托赖着一人有庆，因此上四海无虞。"]'),
('yuanqu-5851','随何赚风魔蒯通・油葫芦','无名氏','元','元曲','yuanqu','','[]','想当日共起亡秦将天下取，都是咱文共武，(带云)老丞相，你寻思咱。',112,'元曲/yuanqu.json','["想当日共起亡秦将天下取，都是咱文共武，(带云)老丞相，你寻思咱。", "(唱)有那个敢和项王交马决赢输？若是那韩淮阴不肯辞西楚，只这汉高皇怕不闷死在巴蜀！因此上我张良操一纸书，你个萧丞相曾三荐举。", "将元戎百万坛台筑，可不道君子断其初。"]'),
('yuanqu-5852','随何赚风魔蒯通・天下乐','无名氏','元','元曲','yuanqu','','[]','现如今百二山河壮帝居，他则望迁也波除，倒将他剑下诛，可不道举枉错直民不服。',64,'元曲/yuanqu.json','["现如今百二山河壮帝居，他则望迁也波除，倒将他剑下诛，可不道举枉错直民不服。", "老夫不是厮卖弄，丞相你也须自窨付，端的是谁推翻楚项羽。"]'),
('yuanqu-5853','随何赚风魔蒯通・那吒令','无名氏','元','元曲','yuanqu','','[]','你起初时要他，便推轮捧毂；后来时怕他，慌封侯蹑足；到今时忌他，便待将杀身也那灭族！他立下十大功，合请受万钟禄，恁将他百样妆诬！。',64,'元曲/yuanqu.json','["你起初时要他，便推轮捧毂；后来时怕他，慌封侯蹑足；到今时忌他，便待将杀身也那灭族！他立下十大功，合请受万钟禄，恁将他百样妆诬！。"]'),
('yuanqu-5854','随何赚风魔蒯通・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','他、他、他击陈馀，有权术；擒夏悦，用机谋。',55,'元曲/yuanqu.json','["他、他、他击陈馀，有权术；擒夏悦，用机谋。", "他可便堰住淮河，夜斩龙且，将魏豹智虏，将齐王力取，论功劳今古全无！。"]'),
('yuanqu-5855','随何赚风魔蒯通・寄生草','无名氏','元','元曲','yuanqu','','[]','九里山按形势，八卦阵列士卒。',68,'元曲/yuanqu.json','["九里山按形势，八卦阵列士卒。", "亏杀俺韩元帅，自把先锋做。", "遣五侯赶到合休处，赚重瞳走入阴陵路。", "遮莫他乌骓能突数重围，怎当的乌江那日无船渡！。"]'),
('yuanqu-5856','随何赚风魔蒯通・金盏儿','无名氏','元','元曲','yuanqu','','[]','我从今见盈虚，识乘除。',194,'元曲/yuanqu.json','["我从今见盈虚，识乘除。", "总不如隐山林弃钟鼎，倒可也无荣辱。", "早拜辞了龙楼凤阁，只守着我这蜗庐。", "我甘心儿追四皓，回首也叹三闾。", "(萧相云)老司徒，你见我门排画戟，户列椒图，可不好那。", "(正末唱)谁待要你这门排双画戟，户列八椒图！(樊哙云)丞相，我说道不要请他，他又不会主张。", "这桩事毕竟怎了也？(萧相云)樊将军且慢者，等司徒回去了再做计较。", "(正末云)老丞相勿罪。", "老夫如今就向山中修行办道去也。", "(唱)。"]'),
('yuanqu-5857','随何赚风魔蒯通・赚煞尾','无名氏','元','元曲','yuanqu','','[]','我如今跳出是非场，抹下了这功劳簿。',97,'元曲/yuanqu.json','["我如今跳出是非场，抹下了这功劳簿。", "只待要修仙辟谷，倒是俺散袒逍遥一愿足。", "再休提玉带金鱼，细踌躇、究竟何如，只俺可不诫前车与后车。", "眼见的三齐王受屈，因此上子房公归去，一任那太平天子百灵扶。", "(下)。"]'),
('yuanqu-5858','随何赚风魔蒯通・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','当初你假镇三齐，他拜真王也非实意。',65,'元曲/yuanqu.json','["当初你假镇三齐，他拜真王也非实意。", "不甫能定江山拱手垂衣，投至得国无争，家无讼，端的是非同容易！今日个万国来仪，见你握兵权便生疑忌。"]'),
('yuanqu-5859','随何赚风魔蒯通・醉春风','无名氏','元','元曲','yuanqu','','[]','没来由平净了楚干戈，扶持了汉社稷。',307,'元曲/yuanqu.json','["没来由平净了楚干戈，扶持了汉社稷。", "(韩信云)想某费了多少力气。", "方才灭的那西楚霸王。", "扶助圣人，平定天下，圣人岂有负了我的？我便走一遭去，怕做甚么！(正末唱)常言道\"太平不用旧将军\"，可怎生参不透这个理、理！(云)元帅，我想你立下这等大功劳，今日被他疑忌，则不如纳下朝章，趁一带青山，逍遥散诞，可不好也。", "(唱)你便不能卸职休官，也须要思前算后，做一个保身长计。", "(韩信云)蒯彻，想某南征北讨。", "东荡西除，立下十大功劳，料的圣人怎好便负了我也？(正末云)元帅，不可去。", "若去呵，必受其祸。", "(韩信云)删彻，你差矣！俺想圣人平日解衣衣我，推食食我。", "这许多好意。", "难道今日便负了我？必无此理。", "(正末云)元帅若依我呵，万无一失。", "(唱)。"]'),
('yuanqu-5860','随何赚风魔蒯通・上小楼','无名氏','元','元曲','yuanqu','','[]','你去后多凶少吉，干这般尽忠竭力。',216,'元曲/yuanqu.json','["你去后多凶少吉，干这般尽忠竭力。", "(带云)岂不闻古人有云：(唱)威而不猛，高而不危，满而不溢。", "你休性执，劝不的，还待要争名夺利，(带云)若不依蒯彻之言呵，(唱)管送的你死无葬身之地。", "(云)元帅，我劝你只不如学那范蠡、张良，早弃官而去，倒落的个远害全身也。", "(韩信云)蒯彻，你差矣。", "想为官的前呼后拥，衣轻乘肥，有多少荣耀。", "平白地可倒修行办道，餐松啖柏，革履麻绦，受这等苦来！(正末做笑科，云)元帅，你道这两个人埋名隐迹，却是为何？(唱)。"]'),
('yuanqu-5861','随何赚风魔蒯通・幺篇','无名氏','元','元曲','yuanqu','','[]','那一个霸越的有计策，一个兴汉的好事绩。',255,'元曲/yuanqu.json','["那一个霸越的有计策，一个兴汉的好事绩。", "他为甚么远着红尘，守着青山，挨着黄齑。", "也只是养道德，躲是非，别无主意。", "(带云)我今日劝你，也不为别来。", "(唱)我则怕你祸临头急难涌退。", "(韩信云)蒯彻，我此去料无甚事，你但放心者。", "(正末云)元帅，不是我蒯彻阻当你，千万不可去。", "若不听蒯彻之言，我家有老母，即日须当拜辞元帅，回家侍养母亲去也。", "(韩信云)蒯彻，你放心。", "我见了圣人，不久也就回来，你怎便要辞了我去？(正末云)既然如此，你主意要去。", "令人与我将的那纸钱水饭过来。", "(卒子云)理会的。", "(卒子拿纸钱水饭当面前祭科)(正末唱)。"]'),
('yuanqu-5862','随何赚风魔蒯通・朝天子','无名氏','元','元曲','yuanqu','','[]','我说知就里。',168,'元曲/yuanqu.json','["我说知就里。", "想蒯彻也无他意，趁着你在日浇奠理当宜，若死了空迎祭。", "(云)元帅，你比那两个人如何？(韩信云)可是那两个人？(正末唱)我想那雍齿合诛，丁公无罪。", "汉萧何忒下的，救他出井底，倒将他斩讫。", "那的也须放着傍州例。", "(韩信云)蒯彻，你且回去。", "某只明日领了数百个军卒，入朝见圣人去来。", "(正末云)元帅，你若到其间，休说我蒯文通不劝你来。", "(唱)。"]'),
('yuanqu-5863','随何赚风魔蒯通・耍孩儿','无名氏','元','元曲','yuanqu','','[]','今日个萧何反问施谋智，黑洞洞不知一个的实。',115,'元曲/yuanqu.json','["今日个萧何反问施谋智，黑洞洞不知一个的实。", "若将军一脚到京畿，但踏着消息儿你可也便身亏。", "他安排着香饵把鳌龟钓，准备着窝弓将虎豹射。", "咱人泰极多生否，(韩信云)圣人要游云梦山去，宣某为留守哩。", "(正末唱)再休想吉祥如意，多管是你恶限临逼。"]'),
('yuanqu-5864','随何赚风魔蒯通・煞尾','无名氏','元','元曲','yuanqu','','[]','我如今、我如今难劝你、难劝你，再休想驱兵领将元戎职，少不的做个背井离乡横死鬼。',43,'元曲/yuanqu.json','["我如今、我如今难劝你、难劝你，再休想驱兵领将元戎职，少不的做个背井离乡横死鬼。", "(下)。"]'),
('yuanqu-5865','随何赚风魔蒯通・金蕉叶','无名氏','元','元曲','yuanqu','','[]','则落你好似披麻救火，蒯彻也不似那般人随风倒舵。',42,'元曲/yuanqu.json','["则落你好似披麻救火，蒯彻也不似那般人随风倒舵。", "事冗也辞身涌脱，今日个慌顿断名缰利锁。"]'),
('yuanqu-5866','随何赚风魔蒯通・鬼三台','无名氏','元','元曲','yuanqu','','[]','夜深也咱独坐，谁想道人瞧破，呀，早将我这佯狂败脱。',150,'元曲/yuanqu.json','["夜深也咱独坐，谁想道人瞧破，呀，早将我这佯狂败脱。", "(随何云)蒯文通，你有诳君之罪。", "圣人宣你入朝，你不合诈妆风魔也。", "(正末唱)便死后待如何，我舍不的兰堂画阁，任从他利名相定夺。", "我死呵一任入鼎镬，你、你、你，休则管掀扬也波搬唆。", "(随何云)奉萧丞相的言语，着我来请你入朝。", "到来日便索和俺同行也。", "(正末唱)。"]'),
('yuanqu-5867','随何赚风魔蒯通・调笑令','无名氏','元','元曲','yuanqu','','[]','他、他、他，做事儿太过，谁免的没风波，呀，常言道点点还来入旧窝。',81,'元曲/yuanqu.json','["他、他、他，做事儿太过，谁免的没风波，呀，常言道点点还来入旧窝。", "俺想着大梁王破楚功劳大，更和那九江王十分的骁果。", "也全亏杀俺韩元帅智量多，端的是那一个替你扫荡干戈。"]'),
('yuanqu-5868','随何赚风魔蒯通・秃厮儿','无名氏','元','元曲','yuanqu','','[]','我为甚的呆邓邓把衣裳袒裸，乱蓬蓬把鬓发婆娑。',48,'元曲/yuanqu.json','["我为甚的呆邓邓把衣裳袒裸，乱蓬蓬把鬓发婆娑。", "白日里叫吖吖信口自嘲歌，到晚来向羊圈里且存活、消磨。"]'),
('yuanqu-5869','随何赚风魔蒯通・圣药王','无名氏','元','元曲','yuanqu','','[]','你待胡扯撮、强领掇，道俺蒯文通故意作风魔。',53,'元曲/yuanqu.json','["你待胡扯撮、强领掇，道俺蒯文通故意作风魔。", "须不是我忒口多、忒意多，也只为谁人立起这山河，怎做一枕梦南柯！。"]'),
('yuanqu-5870','随何赚风魔蒯通・收尾','无名氏','元','元曲','yuanqu','','[]','想着他开疆展土将君王佐，这的是收园结果。',46,'元曲/yuanqu.json','["想着他开疆展土将君王佐，这的是收园结果。", "当日个未央宫枉图了他，今日个汉萧何又觑着我。", "(下)。"]'),
('yuanqu-5871','随何赚风魔蒯通・双调/新水令','无名氏','元','元曲','yuanqu','','[]','我想那辞朝归去汉张良，早赚的个韩元帅一时身丧。',435,'元曲/yuanqu.json','["我想那辞朝归去汉张良，早赚的个韩元帅一时身丧。", "苦也波擎天白玉柱，痛也波架海紫金梁。", "那些个展土开疆，生扭做歹勾当。", "(云)令人，报复去。", "道有蒯彻在于门首。", "(祗候报科，云)有蒯彻在于门首。", "(萧相云)着他过来。", "(祗候云)着过去。", "(见科)(正末假意跳油镬科)(萧相云)住！住！住！蒯文通，你为何不言不语，便往油镬中跳去？这等不怕死那！(樊哙云)此人不可问他，若问呵必然要下说词也。", "(正末云)自如蒯彻有罪。", "岂望生乎？(萧相云)当初韩信是你教唆他来？(正末云)是蒯彻教唆他来。", "(萧相云)现有汉天子在上，你不肯辅佐，倒去顺那韩信。", "(正末云)丞相你岂不知。", "桀犬吠尧，尧非不仁，犬固吠非其主也。", "当那一日我蒯彻则知有韩信，不知有甚么汉天子。", "吾受韩信衣食。", "岂不要知恩报恩乎？(萧相云)想韩信才定三齐，便请做假王以镇之。", "这明明有反叛之意，理当斩首。", "(正末云)嗨！丞相说那里话，我想汉天子所以得天下，是靠着谁来？运筹决策，多赖张良；战胜攻取，多赖俺韩元帅。", "如今闲的闲了，斩的斩了，岂不理当！(唱)。"]'),
('yuanqu-5872','随何赚风魔蒯通・驻马听','无名氏','元','元曲','yuanqu','','[]','那张良治国安邦。',490,'元曲/yuanqu.json','["那张良治国安邦。", "扶的汉主登基霸主亡。", "韩信他驱兵领将。", "直会的真龙出世假龙藏。", "杀得个满身鲜血卧沙场，才博的这一方金印来收掌。", "你、你、你，今日也理当，怕不做凤凰飞在梧桐上。", "(萧相云)想当初主公起兵汉中，多亏了众位功臣，也不专靠那韩信一人之力。", "(正末云)我想楚汉争锋，鸿沟为界。", "那时节俺韩元帅投楚则楚胜，投汉则汉胜。", "天下之势，决于一人。", "我因此屡屡劝韩元帅留下项王，决个鼎足三分之计。", "怎当他不信忠言，致令身遭白刃。", "屈死了盖世英雄，岂不可惜！丞相，只你当初也曾保举他来，成也是你，败也是你。", "我蒯彻做不得反面的人，惟有一死，可报韩元帅于地下。", "(做跳科)(萧相云)令人，且与我挡住者。", "(樊哙云)蒯文通，韩信说是你搬调他来，你正是个通同谋反的人，当得认罪。", "(萧相云)樊将军，你说的是。", "想他在韩信手下为辩士。", "正是他心腹之人。", "律法有云：\"一人造反，九族全诛\"，何况他是通同谋反的。", "今日便将他油锅烹了，也不为枉。", "(正末云)丞相，我想汉王在南郑之时，雄兵骁将，莫知其数，然没一个能敌项王者。", "后来得了韩信，筑起三丈高台，拜他为帅，杀得项王不渡乌江，自刎而死。", "如今天下太平，更要韩信做甚么？斩便斩了，不为妨害。"]'),
('yuanqu-5873','随何赚风魔蒯通・乔牌儿','无名氏','元','元曲','yuanqu','','[]','众公卿多感伤，诸文武尽悲怆。',36,'元曲/yuanqu.json','["众公卿多感伤，诸文武尽悲怆。", "连那汉萧何泪滴在罗袍上，你正是死了也空念想。"]'),
('yuanqu-5874','随何赚风魔蒯通・挂玉钩','无名氏','元','元曲','yuanqu','','[]','想起那韩元帅葫芦提斩在法场，将功劳簿都做招伏状。',163,'元曲/yuanqu.json','["想起那韩元帅葫芦提斩在法场，将功劳簿都做招伏状。", "恰便似哑双倾杯反受殃，枉了这五年间把烟尘荡。", "才博的个三齐王。", "又不得终身享。", "哎！谁知你这宰相厅前，倒做了闹市云阳。", "(曹参云)嗨，丞相，想韩信立下如此功劳，也不当就将他杀坏了也。", "(萧相云)可知道韩信是屈死了的。", "但死者不能复生，我如今便要救他，事已无及。", "如之奈何？(正末做笑科，唱)。"]'),
('yuanqu-5875','随何赚风魔蒯通・雁儿落','无名氏','元','元曲','yuanqu','','[]','笑杀我蒯文通舌辨强，怎出的你萧丞相机谋广。',39,'元曲/yuanqu.json','["笑杀我蒯文通舌辨强，怎出的你萧丞相机谋广。", "要诛的便着刀下诛，要向的便把心儿向。"]'),
('yuanqu-5876','随何赚风魔蒯通・得胜令','无名氏','元','元曲','yuanqu','','[]','呀，畅好是没算计的汉贤良，左使着这一片狠心肠。',78,'元曲/yuanqu.json','["呀，畅好是没算计的汉贤良，左使着这一片狠心肠。", "早知道屈死了韩元帅，何不还留他楚霸王。", "图甚么风光，待气昂昂端坐在中军帐；只不如守着农庄，倒也稳拍拍常为田舍郎。"]'),
('yuanqu-5877','随何赚风魔蒯通・沽美酒','无名氏','元','元曲','yuanqu','','[]','兀的不是狡兔死走狗僵，高鸟尽劲弓藏，也枉了你荐举他来这一场。',49,'元曲/yuanqu.json','["兀的不是狡兔死走狗僵，高鸟尽劲弓藏，也枉了你荐举他来这一场。", "把当日个筑台拜将，到今日又待要筑坟堂。"]'),
('yuanqu-5878','随何赚风魔蒯通・太平令','无名氏','元','元曲','yuanqu','','[]','便做有春秋祭飨，也济不得他九泉下魂魄凄凉。',68,'元曲/yuanqu.json','["便做有春秋祭飨，也济不得他九泉下魂魄凄凉。", "倒不如早将我油烹火葬，好和他死生厮傍。", "我可也不慌，不忙，还含笑的就亡，呀，这便算做你加官赐赏。"]'),
('yuanqu-5879','随何赚风魔蒯通・鸳鸯煞','无名氏','元','元曲','yuanqu','','[]','若是汉天子早把书明降，韩元帅免受人诬罔。',114,'元曲/yuanqu.json','["若是汉天子早把书明降，韩元帅免受人诬罔。", "可不的带砺河山，盟言无恙。", "我蒯彻也妆甚么风魔，使甚么伎俩。", "(还冠带科，唱)这冠带呵添不得我荣光！(还黄金科唱)这金呵铸不得他黄金像！只要你个萧丞相自去思量，怎生的屈杀了什大功臣被万民讲！。"]'),
('yuanqu-5880','梁州・叹落落情怀不己，恨匆匆岁月何之。拥并也似一片闲愁撺掇出伤心','詹时雨','元','元曲','yuanqu','','[]','故事。',121,'元曲/yuanqu.json','["故事。", "往常时花笺写恨，红叶题诗，都做了风中飞絮，水上浮萍。", "痛杀杀玉连环掂的瑕疵。", "碜可可锦回纹揉的参差。", "瘦廉纤对妆奁金粉慵施，愁荏苒秀房中拈针慵使，病淹渐锦筝挡金柱慵支。", "念兹。", "对此，匆匆岁月三之二，恰初三早初四。", "呖呖风前孤雁儿，感起我一弄嗟咨。"]'),
('yuanqu-5881','尾声・雁儿你写西风曲似苍颉字，对南浦愁如宋玉词。恰春归，早秋至，','詹时雨','元','元曲','yuanqu','','[]','多寒温，少传示；恼人肠，聒人耳，碎人心，堕人志。',52,'元曲/yuanqu.json','["多寒温，少传示；恼人肠，聒人耳，碎人心，堕人志。", "雁儿则被你撺掇出无限相思，偏怎生不寄俺有情分故人书半纸。"]'),
('yuanqu-5882','醋葫芦・枪攒呵玉臂擎，箭来呵罗袜挑。丁香舌吐似剑吹毛。连珠炮被窝','詹时雨','元','元曲','yuanqu','','[]','儿里聒破脑。',26,'元曲/yuanqu.json','["儿里聒破脑。", "知音的都道，我不信建头功先奏你个女妖娆。"]'),
('yuanqu-5883','二・铰青丝缠做弩弦，裁香罗衲做战袄。补旗幡绞断翠裙腰，金疮药细将','詹时雨','元','元曲','yuanqu','','[]','脂粉调。',24,'元曲/yuanqu.json','["脂粉调。", "都是些风流功效，他则想五花诰飞下紫宸朝。"]'),
('yuanqu-5884','三・叫喳喳锦缆移，闹垓垓画桨摇。那里取明眸皓齿姆军稍，更做道孙武','詹时雨','元','元曲','yuanqu','','[]','子教得来武艺高。',27,'元曲/yuanqu.json','["子教得来武艺高。", "上不过提铃喝号，抵多少碧桃花下坐吹箫。"]'),
('yuanqu-5885','四・他恋着逢窗下风致佳，舵楼中景物饶。棹歌声里乐陶陶，辱没杀铺红','詹时雨','元','元曲','yuanqu','','[]','苫绿翡翠巢。',25,'元曲/yuanqu.json','["苫绿翡翠巢。", "握不道相偎相抱，那里也芙蓉帐暖度春宵。"]'),
('yuanqu-5886','随煞・奶奶得了些卖阵钱，哥哥占了些劳军钞。他向这海神庙多买好香烧，','詹时雨','元','元曲','yuanqu','','[]','但只愿一年一度征海岛。',115,'元曲/yuanqu.json','["但只愿一年一度征海岛。", "休忘了将军伯旗帜，他是个玉门关旧日的莽班超。", "客窗值雪倚龙泉数声长叹息，游子去何期。", "添一岁长一分白发，治一经饱一世黄沙。", "风凛凛风晚江空，雪漫漫天阔云低。", "对梅花叹人犹未归，观不足严凝景致。", "玉壶春滟滟，银海夜凄凄。"]'),
('yuanqu-5887','逍遥乐・客窗深闭，止不过香炷龙涎，茶烹凤髓，纸帐低垂。早难道翠倚','詹时雨','元','元曲','yuanqu','','[]','红偎，冷暖年来只自知，捱不彻凄凉滋味。',34,'元曲/yuanqu.json','["红偎，冷暖年来只自知，捱不彻凄凉滋味。", "鸳鸯无梦，鸿雁无音，灵鹊无依。"]'),
('yuanqu-5888','金菊香・看别人吹箫跨凤上瑶池，乘兴扁舟访剡溪。真乃是平地白云三万','詹时雨','元','元曲','yuanqu','','[]','里，堪画堪题。',16,'元曲/yuanqu.json','["里，堪画堪题。", "水昌宫翻做素玻璃。"]'),
('yuanqu-5889','尾声・调琴演楚骚，研朱点《周易》。风流似党进，终日醉如泥。磨龙香','詹时雨','元','元曲','yuanqu','','[]','拂花笺呵冰笔，挥写就乾坤清气，着人道老袁安犹自说兵机。',27,'元曲/yuanqu.json','["拂花笺呵冰笔，挥写就乾坤清气，着人道老袁安犹自说兵机。"]'),
('yuanqu-5890','般涉调・哨遍新建构栏教坊求赞','詹时雨','元','元曲','yuanqu','','[]','圣遍飞龙当日，火精焰焰光天德。',103,'元曲/yuanqu.json','["圣遍飞龙当日，火精焰焰光天德。", "三尺剑一戎衣，笑谈间平吞了万里华夷。", "二气里，八荒跻寿。", "四海涵春，出雍熙治。", "都会金陵佳丽，鲁麟呈瑞，周凤来仪。", "天香荡漾酒旗风，甘露调和落花泥。", "拽塌了旌旗，打灭了烽尘，销溶了剑戟。"]'),
('yuanqu-5891','耍孩儿・赤紧的教坊司独占了阳和地，越显得莺花艳美。真乃是紫微宫殿','詹时雨','元','元曲','yuanqu','','[]','乐星集，另巍巍创立个根基。',70,'元曲/yuanqu.json','["乐星集，另巍巍创立个根基。", "方位里都按着郭景纯经天纬地阴阳诀，规矩上不离了鲁公输迈古超今造化机。", "昏昼里无休息，响玎玎斧斤电掣，闹垓垓锯铲星飞。"]'),
('yuanqu-5892','双调・寿阳曲','阿鲁威','元','元曲','yuanqu','','[]','千年调，一旦空，惟有纸钱灰晚风吹送。',35,'元曲/yuanqu.json','["千年调，一旦空，惟有纸钱灰晚风吹送。", "尽蜀鹃血啼烟树中，唤不回一场春梦。"]'),
('yuanqu-5893','双调・湘妃怨','阿鲁威','元','元曲','yuanqu','','[]','楚天空阔楚天长，一度怀人一断肠。',119,'元曲/yuanqu.json','["楚天空阔楚天长，一度怀人一断肠。", "此心只在肩舆上，倩东风过武昌，助离愁烟水茫茫。", "竹上雨湘妃泪，树中禽蜀帝王，无限思量。", "夜来雨横与风狂，断送西园满地香，晓来蜂蝶空游荡，苦难寻红锦妆。", "问东君归计何忙。", "尽叫得鹃声碎，却教人空断肠，漫劳动送客垂杨。"]'),
('yuanqu-5894','正宫・塞鸿秋','刘庭信','元','元曲','yuanqu','','[]','苏卿写下金山恨，双生得个风流信。',52,'元曲/yuanqu.json','["苏卿写下金山恨，双生得个风流信。", "亚仙不是夫人分，元和到受十年困。", "冯魁到底村，双渐从来嫩，思量惟有王魁俊。"]'),
('yuanqu-5895','正宫・醉太平忆旧','刘庭信','元','元曲','yuanqu','','[]','泥金小简，白玉连环，牵情惹恨两三番。',128,'元曲/yuanqu.json','["泥金小简，白玉连环，牵情惹恨两三番。", "好光阴等闲，景阑珊绣帘风软杨花散。", "泪阑干绿窗雨洒梨花绽，锦澜斑香闺春老杏花残，奈薄情未还。", "走苏卿聪明的志高，懵懂的愚浊。", "一船茶单换了个女妖娆，像章城佛了。", "老卜儿接了鸦青钞，俊苏卿受了金花诰，俏双生披了绿罗袍，村冯魁老曹。"]'),
('yuanqu-5896','中吕・朝天子赴约','刘庭信','元','元曲','yuanqu','','[]','夜深深静悄，明朗朗月高，小书院无人到。',74,'元曲/yuanqu.json','["夜深深静悄，明朗朗月高，小书院无人到。", "书生今夜且休睡着，有句话低低道：半扇儿窗棂，不须轻敲，我来时将花树儿摇。", "你可便记着，便休要忘了。", "影儿动咱来到。"]'),
('yuanqu-5897','双调・雁儿落过得胜令','刘庭信','元','元曲','yuanqu','','[]','懒栽番岳花，学种樊迟稼。',151,'元曲/yuanqu.json','["懒栽番岳花，学种樊迟稼。", "心闲梦寝安，志满忧愁大。", "无福享荣华，有分受贫乏。", "燕度春秋社，蜂喧早晚衙。", "茶瓜，林下渔樵话。", "桑麻，山中宰相家。", "下一局不死棋，论一着长生计。", "服一丸延寿丹，养一口元阳气。", "看一片岭云飞，听一会野猿啼。", "化一钵千家饭，穿一领百衲衣。", "枕一块顽石，落一觉安然睡。", "对一派清溪，悟一生玄妙理。", "套数。"]'),
('yuanqu-5898','正宫・端正好金钱问卜','刘庭信','元','元曲','yuanqu','','[]','香尘暗翠帏屏，花露冷鲛绡帐，闷恹恹画阁兰堂。',37,'元曲/yuanqu.json','["香尘暗翠帏屏，花露冷鲛绡帐，闷恹恹画阁兰堂。", "愁云怨雨风流况，都蹙在眉尖上。"]'),
('yuanqu-5899','倘秀才・展玉腕把春纤合掌，恰便似白莲蕊初生在这藕上，高卷珠帘拜月','刘庭信','元','元曲','yuanqu','','[]','碧梧摇碎影，红药吐狂香，正红稠绿穰。',18,'元曲/yuanqu.json','["碧梧摇碎影，红药吐狂香，正红稠绿穰。"]'),
('yuanqu-5900','滚绣球・启绿窗离了绣房，博山炉把香来拈上，办着片志诚心祷告穹苍，','刘庭信','元','元曲','yuanqu','','[]','低低的念了一会，深深的拜了四方。',60,'元曲/yuanqu.json','["低低的念了一会，深深的拜了四方。", "转秋波又则怕外人偷望，则为咱正青春未配鸾凰。", "甚时得遇乘鸾客？何日相逢傅粉郎？审问个行藏。"]'),
